async function getCampaignImpact(campaignId) {
  const db2 = await getDb();
  if (!db2) return { totalDonors: 0, totalRaised: 0, goal: 0, percentComplete: 0 };
  try {
    const [campaign, donations] = await Promise.all([
      db2.select().from(charityCampaigns).where(eq(charityCampaigns.id, campaignId)).limit(1),
      db2.select().from(charityDonations).where(eq(charityDonations.campaignId, campaignId))
    ]);
    const c = campaign[0];
    if (!c) return { totalDonors: 0, totalRaised: 0, goal: 0, percentComplete: 0 };
    const totalRaised = donations.reduce((sum4, d) => sum4 + Number(d.amount), 0);
    const goal = Number(c.goalAmount);
    return {
      totalDonors: donations.length,
      totalRaised,
      goal,
      percentComplete: goal > 0 ? Math.min(100, Math.round(totalRaised / goal * 100)) : 0
    };
  } catch {
    return { totalDonors: 0, totalRaised: 0, goal: 0, percentComplete: 0 };
  }
}
