async function getStakingStats() {
  const db2 = await getDb();
  if (!db2) return { totalStaked: 0, totalPositions: 0, totalRewardsDistributed: 0, avgApy: 0 };
  try {
    const positions = await db2.select().from(stakingPositions).where(eq(stakingPositions.status, "active"));
    const totalStaked = positions.reduce((sum4, p) => sum4 + Number(p.amount), 0);
    const totalRewards = positions.reduce((sum4, p) => sum4 + Number(p.rewardsEarned), 0);
    const avgApy = positions.length > 0 ? positions.reduce((sum4, p) => sum4 + Number(p.apy), 0) / positions.length : 0;
    return { totalStaked, totalPositions: positions.length, totalRewardsDistributed: totalRewards, avgApy: Math.round(avgApy * 10) / 10 };
  } catch {
    return { totalStaked: 0, totalPositions: 0, totalRewardsDistributed: 0, avgApy: 0 };
  }
}
