var nsfwRouter = router({
  // ─── Age Verification ────────────────────────────────────────────────────
  verifyAge: protectedProcedure.input(
    z3.object({
      method: z3.enum(["dob", "id_upload", "credit_card"]),
      dob: z3.string().optional(),
      idUrl: z3.string().optional(),
      cardLast4: z3.string().optional()
    })
  ).mutation(async ({ ctx, input }) => {
    return verifyAge(ctx.user.id, input.method, {
      dob: input.dob,
      idUrl: input.idUrl,
      cardLast4: input.cardLast4
    });
  }),
  // ─── Content Access Check ────────────────────────────────────────────────
  checkAccess: protectedProcedure.input(
    z3.object({
      creatorId: z3.number(),
      contentType: z3.enum(["free", "subscription", "ppv"]),
      ppvPrice: z3.number().optional()
    })
  ).query(async ({ ctx, input }) => {
    return checkContentAccess(
      ctx.user.id,
      input.creatorId,
      input.contentType,
      input.ppvPrice
    );
  }),
  // ─── Subscription Tiers ──────────────────────────────────────────────────
  getDefaultTiers: publicProcedure.query(() => {
    return SUBSCRIPTION_TIERS;
  }),
  subscribe: protectedProcedure.input(
    z3.object({
      creatorId: z3.number(),
      tier: z3.enum(["fan", "supporter", "vip", "elite"])
    })
  ).mutation(async ({ ctx, input }) => {
    return createSubscription2(ctx.user.id, input.creatorId, input.tier);
  }),
  cancelSubscription: protectedProcedure.input(z3.object({ subscriptionId: z3.number() })).mutation(async ({ ctx, input }) => {
    return cancelSubscription2(ctx.user.id, input.subscriptionId);
  }),
  // ─── Creator Earnings ────────────────────────────────────────────────────
  getEarnings: protectedProcedure.query(async ({ ctx }) => {
    return getCreatorEarnings(ctx.user.id);
  }),
  getContentStats: protectedProcedure.query(async ({ ctx }) => {
    return getCreatorContentStats(ctx.user.id);
  }),
  requestPayout: protectedProcedure.input(
    z3.object({
      amount: z3.number().min(50),
      method: z3.enum(["bank", "crypto", "paypal"]),
      destination: z3.string()
    })
  ).mutation(async ({ ctx, input }) => {
    return requestPayout({
      creatorId: ctx.user.id,
      amount: input.amount,
      method: input.method,
      address: input.destination
    });
  }),
  // ─── Platform Info ───────────────────────────────────────────────────────
  platformFee: publicProcedure.query(() => ({
    platformFeePercent: PLATFORM_FEE_PERCENT,
    creatorKeepPercent: 1 - PLATFORM_FEE_PERCENT,
    payoutMinimum: 50,
    payoutCurrency: ["USD", "SKY444", "USDC"]
  }))
});

