function generateDockerCompose(config) {
  const services = [];
  services.push(`  app:
    build: .
    container_name: ${config.projectName || "shadowchat"}-app
    restart: unless-stopped
    ports:
      - "${config.port || 3e3}:3000"
    environment:
      - NODE_ENV=production
      - DATABASE_URL=mysql://shadowchat:\${DB_PASSWORD}@db:3306/shadowchat
      - REDIS_URL=redis://:\${REDIS_PASSWORD}@redis:6379
      - JWT_SECRET=\${JWT_SECRET}
    depends_on:
      db:
        condition: service_healthy
      ${config.enableRedis ? "redis:\n        condition: service_healthy" : ""}
    volumes:
      - ./logs:/app/logs
    networks:
      - shadowchat-net`);
  services.push(`  db:
    image: mysql:8.0
    container_name: ${config.projectName || "shadowchat"}-db
    restart: unless-stopped
    environment:
      MYSQL_ROOT_PASSWORD: \${DB_PASSWORD}
      MYSQL_DATABASE: shadowchat
      MYSQL_USER: shadowchat
      MYSQL_PASSWORD: \${DB_PASSWORD}
    volumes:
      - db-data:/var/lib/mysql
      - ./init.sql:/docker-entrypoint-initdb.d/init.sql:ro
    healthcheck:
      test: ["CMD", "mysqladmin", "ping", "-h", "localhost"]
      interval: 10s
      timeout: 5s
      retries: 5
    networks:
      - shadowchat-net`);
  if (config.enableRedis) {
    services.push(`  redis:
    image: redis:7-alpine
    container_name: ${config.projectName || "shadowchat"}-redis
    restart: unless-stopped
    command: redis-server --requirepass \${REDIS_PASSWORD} --maxmemory 256mb --maxmemory-policy allkeys-lru
    volumes:
      - redis-data:/data
    healthcheck:
      test: ["CMD", "redis-cli", "--no-auth-warning", "-a", "\${REDIS_PASSWORD}", "ping"]
      interval: 10s
      timeout: 5s
      retries: 5
    networks:
      - shadowchat-net`);
  }
  if (config.enableNginx) {
    services.push(`  nginx:
    image: nginx:alpine
    container_name: ${config.projectName || "shadowchat"}-nginx
    restart: unless-stopped
    ports:
      - "80:80"
      - "443:443"
    volumes:
      - ./nginx.conf:/etc/nginx/nginx.conf:ro
      - ./ssl:/etc/nginx/ssl:ro
      - nginx-cache:/var/cache/nginx
    depends_on:
      - app
    networks:
      - shadowchat-net`);
  }
  return `version: "3.9"

services:
${services.join("\n\n")}

volumes:
  db-data:
  redis-data:
  nginx-cache:

networks:
  shadowchat-net:
    driver: bridge
`;
}
function generateNginxConfig(config) {
  const domain = config.domain || "localhost";
  const ssl = config.enableSSL;
  return `events {
  worker_connections 1024;
}

http {
  upstream shadowchat_app {
    server app:${config.port || 3e3};
    keepalive 32;
  }

  # Rate limiting
  limit_req_zone $binary_remote_addr zone=api:10m rate=100r/m;
  limit_req_zone $binary_remote_addr zone=auth:10m rate=10r/m;

  ${ssl ? `server {
    listen 80;
    server_name ${domain};
    return 301 https://$host$request_uri;
  }

  server {
    listen 443 ssl http2;
    server_name ${domain};

    ssl_certificate /etc/nginx/ssl/cert.pem;
    ssl_certificate_key /etc/nginx/ssl/key.pem;
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256;
    ssl_prefer_server_ciphers off;` : `server {
    listen 80;
    server_name ${domain};`}

    # Security headers
    add_header X-Frame-Options DENY;
    add_header X-Content-Type-Options nosniff;
    add_header X-XSS-Protection "1; mode=block";
    add_header Referrer-Policy strict-origin-when-cross-origin;

    # Gzip
    gzip on;
    gzip_types text/plain application/json application/javascript text/css;

    location /api/trpc {
      limit_req zone=api burst=20 nodelay;
      proxy_pass http://shadowchat_app;
      proxy_http_version 1.1;
      proxy_set_header Upgrade $http_upgrade;
      proxy_set_header Connection "upgrade";
      proxy_set_header Host $host;
      proxy_set_header X-Real-IP $remote_addr;
      proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
      proxy_set_header X-Forwarded-Proto $scheme;
    }

    location /api/oauth {
      limit_req zone=auth burst=5 nodelay;
      proxy_pass http://shadowchat_app;
      proxy_set_header Host $host;
      proxy_set_header X-Real-IP $remote_addr;
      proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
      proxy_set_header X-Forwarded-Proto $scheme;
    }

    location / {
      proxy_pass http://shadowchat_app;
      proxy_http_version 1.1;
      proxy_set_header Upgrade $http_upgrade;
      proxy_set_header Connection "upgrade";
      proxy_set_header Host $host;
      proxy_set_header X-Real-IP $remote_addr;
      proxy_cache_bypass $http_upgrade;
    }
  }
}
`;
}
