async function runHealthChecks() {
  const results = [];
  const start = Date.now();
  results.push({
    service: "App Server",
    status: "healthy",
    latency: Date.now() - start,
    message: "Express server running"
  });
  try {
    const dbStart = Date.now();
    await Promise.resolve().then(() => (init_db(), db_exports)).then(({ db: db2 }) => db2.execute("SELECT 1"));
    results.push({
      service: "Database",
      status: "healthy",
      latency: Date.now() - dbStart,
      message: "MySQL connection OK"
    });
  } catch (e) {
    results.push({
      service: "Database",
      status: "down",
      latency: 0,
      message: String(e)
    });
  }
  return results;
}

