function generateCOA(print, purchaserId) {
  const purchaseDate = (/* @__PURE__ */ new Date()).toISOString().split("T")[0];
  const signature = crypto3.createHmac("sha256", "skyler-blue-spillers-private-key").update(`${print.id}-${purchaserId}-${purchaseDate}`).digest("hex");
  return {
    printId: print.id,
    title: print.title,
    artist: "Skyler Blue Spillers",
    edition: `${print.edition} of ${print.totalEdition}`,
    purchaseDate,
    purchaserId,
    coaHash: print.coaHash,
    signature,
    blockchain: "Ethereum",
    txHash: `0x${crypto3.randomBytes(32).toString("hex")}`
  };
}
function calculateTechNetWorth() {
  const breakdown = {
    "Platform codebase (200K+ lines)": 2e5 * 75,
    "AI/ML models and training data": 5e5,
    "Database schemas and migrations": 5e4,
    "Infrastructure and DevOps": 1e5,
    "Brand and IP": 25e4,
    "Community and user base": 1e6,
    "SKY444 token ecosystem": 2e6,
    "Creator economy platform": 75e4
  };
  const totalLines = 2e5;
  const estimatedValue = Object.values(breakdown).reduce((a, b) => a + b, 0);
  return { totalLines, estimatedValue, breakdown };
}

// server/digital-art-router.ts
init_notification();
var digitalArtRouter = router({
  // ─── Print Catalog ───────────────────────────────────────────────────────
  getPrints: publicProcedure.input(
    z5.object({
      series: z5.string().optional(),
      currency: z5.enum(["USD", "SKY444"]).optional()
    })
  ).query(async ({ input }) => {
    const catalog = generatePrintCatalog();
    let filtered = catalog;
    if (input.series) {
      filtered = filtered.filter((p) => p.series === input.series);
    }
    return filtered;
  }),
  // ─── Coded Tools ─────────────────────────────────────────────────────────
  getTools: publicProcedure.query(() => {
    return CODED_TOOLS;
  }),
  // ─── Certificate of Authenticity ─────────────────────────────────────────
  generateCOA: protectedProcedure.input(
    z5.object({
      printId: z5.string(),
      buyerName: z5.string(),
      buyerWallet: z5.string().optional()
    })
  ).mutation(async ({ ctx, input }) => {
    const catalog = generatePrintCatalog();
    const print = catalog.find((p) => p.id === input.printId);
    if (!print) throw new Error("Print not found");
    return generateCOA(print, ctx.user.id);
  }),
  // ─── Tech Net Worth ───────────────────────────────────────────────────────
  getTechNetWorth: publicProcedure.query(() => {
    return calculateTechNetWorth();
  }),
  // ─── Series List ─────────────────────────────────────────────────────────
  getSeries: publicProcedure.query(() => {
    const catalog = generatePrintCatalog();
    const series = [...new Set(catalog.map((p) => p.series))];
    return series.map((s) => ({
      name: s,
      count: catalog.filter((p) => p.series === s).length,
      priceRange: {
        min: Math.min(...catalog.filter((p) => p.series === s).map((p) => p.price)),
        max: Math.max(...catalog.filter((p) => p.series === s).map((p) => p.price))
      }
    }));
  }),
  // ─── Checkout (Stripe) ───────────────────────────────────────────────────
  checkout: protectedProcedure.input(
    z5.object({
      items: z5.array(
        z5.object({
          id: z5.string(),
          title: z5.string(),
          price: z5.number(),
          quantity: z5.number().default(1)
        })
      ),
      successUrl: z5.string(),
      cancelUrl: z5.string()
    })
  ).mutation(async ({ ctx, input }) => {
    const total = input.items.reduce((sum4, item) => sum4 + item.price * item.quantity, 0);
    const itemNames = input.items.map((i) => i.title).join(", ");
    await notifyOwner({
      title: `\u{1F3A8} New Digital Art Order \u2014 $${total}`,
      content: `User ${ctx.user.id} purchased: ${itemNames} (Total: $${total})`
    });
    try {
      const { createCheckoutSession: createCheckoutSession2 } = await Promise.resolve().then(() => (init_stripe_skycoin(), stripe_skycoin_exports));
      const orderId = Date.now();
      const session = await createCheckoutSession2(
        orderId,
        ctx.user.id,
        total,
        input.successUrl,
        input.cancelUrl
      );
      return {
        sessionId: session.id,
        url: session.url,
        mock: false
      };
    } catch {
      return {
        sessionId: `art_mock_${Date.now()}`,
        url: `${input.successUrl}?mock=1&items=${encodeURIComponent(itemNames)}&total=${total}`,
        mock: true
      };
    }
  })
});

// server/shadow-identity-router.ts
init_drizzle();
init_db();
init_llm();
import { z as z6 } from "zod";
import { eq as eq5, desc as desc4 } from "drizzle-orm";
function generateShadowId(userId) {
  const salt = 17476;
  const hash = (userId * 7919 + salt) % 1e6;
  return `shadow_${hash.toString(36).toUpperCase().padStart(4, "0")}`;
}
function computeReputationTier(behavior, toxicity, contribution, reliability) {
  const composite = behavior * 0.3 + contribution * 0.3 + reliability * 0.25 - toxicity * 0.15;
  if (composite >= 85) return "LEGENDARY";
  if (composite >= 70) return "TRUSTED";
  if (composite >= 55) return "ESTABLISHED";
  if (composite >= 40) return "RISING";
  if (composite >= 25) return "NEW";
  return "RESTRICTED";
}
var shadowIdentityRouter = router({
  // Get current user's shadow identity profile
  getMyIdentity: protectedProcedure.query(async ({ ctx }) => {
    const user = await getUserById(ctx.user.id);
    if (!user) throw new Error("User not found");
    let shadowId = user.shadowId;
    if (!shadowId) {
      shadowId = generateShadowId(ctx.user.id);
      const _db2 = await getDb();
      if (_db2) await _db2.update(users).set({ shadowId }).where(eq5(users.id, ctx.user.id));
    }
    const behavior = user.behaviorScore ?? 50;
    const toxicity = user.toxicityScore ?? 0;
    const contribution = user.contributionScore ?? 0;
    const reliability = user.reliabilityScore ?? 50;
    return {
      shadowId,
      identityMode: user.identityMode ?? "social",
      verifiedReveal: user.verifiedReveal ?? false,
      scores: {
        behavior,
        toxicity,
        contribution,
        reliability,
        composite: Math.round(behavior * 0.3 + contribution * 0.3 + reliability * 0.25 - toxicity * 0.15)
      },
      reputationTier: computeReputationTier(behavior, toxicity, contribution, reliability),
      displayName: getDisplayName(user, user.identityMode ?? "social"),
      displayAvatar: getDisplayAvatar(user, user.identityMode ?? "social")
    };
  }),
  // Switch identity mode
  setIdentityMode: protectedProcedure.input(z6.object({
    mode: z6.enum(["shadow", "semi", "social", "public"])
  })).mutation(async ({ ctx, input }) => {
    const _db2 = await getDb();
    if (_db2) await _db2.update(users).set({ identityMode: input.mode }).where(eq5(users.id, ctx.user.id));
    return { success: true, mode: input.mode };
  }),
  // Toggle verified reveal
  toggleVerifiedReveal: protectedProcedure.mutation(async ({ ctx }) => {
    const user = await getUserById(ctx.user.id);
    const current = user?.verifiedReveal ?? false;
    const _db2 = await getDb();
    if (_db2) await _db2.update(users).set({ verifiedReveal: !current }).where(eq5(users.id, ctx.user.id));
    return { verifiedReveal: !current };
  }),
  // Get public identity of any user (respects their mode)
  getPublicIdentity: publicProcedure.input(z6.object({ userId: z6.number() })).query(async ({ input }) => {
    const user = await getUserById(input.userId);
    if (!user) return null;
    const mode = user.identityMode ?? "social";
    return {
      shadowId: user.shadowId ?? generateShadowId(input.userId),
      identityMode: mode,
      displayName: getDisplayName(user, mode),
      displayAvatar: getDisplayAvatar(user, mode),
      reputationTier: computeReputationTier(
        user.behaviorScore ?? 50,
        user.toxicityScore ?? 0,
        user.contributionScore ?? 0,
        user.reliabilityScore ?? 50
      ),
      verifiedReveal: user.verifiedReveal ?? false,
      realName: user.verifiedReveal ? user.name : null
    };
  }),
  // AI-powered reputation analysis
  getReputationAnalysis: protectedProcedure.query(async ({ ctx }) => {
    const user = await getUserById(ctx.user.id);
    if (!user) throw new Error("User not found");
    const behavior = user.behaviorScore ?? 50;
    const toxicity = user.toxicityScore ?? 0;
    const contribution = user.contributionScore ?? 0;
    const reliability = user.reliabilityScore ?? 50;
    const tier = computeReputationTier(behavior, toxicity, contribution, reliability);
    const response = await invokeLLM({
      messages: [
        {
          role: "system",
          content: "You are a reputation analyst for a Web3 social platform. Provide a brief 2-sentence insight about a user's reputation profile. Be constructive and specific."
        },
        {
          role: "user",
          content: `User reputation data: Behavior=${behavior}/100, Toxicity=${toxicity}/100, Contribution=${contribution}/100, Reliability=${reliability}/100, Tier=${tier}. Give actionable insight.`
        }
      ]
    });
    const rawContent = response.choices?.[0]?.message?.content;
    const insight = typeof rawContent === "string" ? rawContent : "Keep engaging positively to build your reputation.";
    return {
      tier,
      scores: { behavior, toxicity, contribution, reliability },
      insight,
      recommendations: getRecommendations(behavior, toxicity, contribution, reliability)
    };
  }),
  // Update behavior score (called by system actions)
  recordBehaviorEvent: protectedProcedure.input(z6.object({
    event: z6.enum(["post", "like", "comment", "report_received", "report_filed", "tip_sent", "tip_received", "stream", "stake"])
  })).mutation(async ({ ctx, input }) => {
    const user = await getUserById(ctx.user.id);
    if (!user) return;
    const current = {
      behavior: user.behaviorScore ?? 50,
      toxicity: user.toxicityScore ?? 0,
      contribution: user.contributionScore ?? 0,
      reliability: user.reliabilityScore ?? 50
    };
    const deltas = {
      post: { contribution: 2, reliability: 1 },
      like: { behavior: 1 },
      comment: { contribution: 1, behavior: 1 },
      report_received: { toxicity: 5, behavior: -3 },
      report_filed: { reliability: 1 },
      tip_sent: { contribution: 3, behavior: 2 },
      tip_received: { contribution: 2 },
      stream: { contribution: 4, reliability: 2 },
      stake: { reliability: 3, behavior: 1 }
    };
    const delta = deltas[input.event] ?? {};
    const clamp3 = (v) => Math.max(0, Math.min(100, v));
    const _db2 = await getDb();
    if (_db2) await _db2.update(users).set({
      behaviorScore: clamp3(current.behavior + (delta.behavior ?? 0)),
      toxicityScore: clamp3(current.toxicity + (delta.toxicity ?? 0)),
      contributionScore: clamp3(current.contribution + (delta.contribution ?? 0)),
      reliabilityScore: clamp3(current.reliability + (delta.reliability ?? 0))
    }).where(eq5(users.id, ctx.user.id));
    return { success: true };
  }),
  // Leaderboard of top reputation users
  getReputationLeaderboard: publicProcedure.query(async () => {
    const _db2 = await getDb();
    const topUsers = _db2 ? await _db2.select().from(users).orderBy(desc4(users.reputation)).limit(20).catch(() => []) : [];
    return topUsers.map((u) => ({
      id: u.id,
      shadowId: u.shadowId ?? generateShadowId(u.id),
      displayName: getDisplayName(u, u.identityMode ?? "social"),
      displayAvatar: getDisplayAvatar(u, u.identityMode ?? "social"),
      reputationTier: computeReputationTier(
        u.behaviorScore ?? 50,
        u.toxicityScore ?? 0,
        u.contributionScore ?? 0,
        u.reliabilityScore ?? 50
      ),
      composite: Math.round(
        (u.behaviorScore ?? 50) * 0.3 + (u.contributionScore ?? 0) * 0.3 + (u.reliabilityScore ?? 50) * 0.25 - (u.toxicityScore ?? 0) * 0.15
      )
    }));
  })
});
function getDisplayName(user, mode) {
  switch (mode) {
    case "shadow":
      return user.shadowId ?? generateShadowId(user.id);
    case "semi":
      return user.displayName ?? user.shadowId ?? generateShadowId(user.id);
    case "social":
      return user.displayName ?? user.name ?? "User";
    case "public":
      return user.name ?? user.displayName ?? "User";
    default:
      return user.displayName ?? user.name ?? "User";
  }
}
function getDisplayAvatar(user, mode) {
  if (mode === "shadow") return null;
  return user.avatar ?? null;
}
function getRecommendations(behavior, toxicity, contribution, reliability) {
  const recs = [];
  if (behavior < 50) recs.push("Engage more positively with the community");
  if (toxicity > 20) recs.push("Reduce flagged content to lower your toxicity score");
  if (contribution < 30) recs.push("Post, tip, and stream to boost your contribution score");
  if (reliability < 40) recs.push("Stake SKY444 and maintain consistent activity to improve reliability");
  if (recs.length === 0) recs.push("Keep up the great work \u2014 you're a trusted community member!");
  return recs;
}

// server/notification-intelligence-router.ts
import { z as z7 } from "zod";
init_db();
init_llm();
import { sql as sql2 } from "drizzle-orm";
var PRIORITY_WEIGHTS = {
  // Critical — always immediate
  security_alert: 100,
  payment_received: 95,
  withdrawal_complete: 95,
  account_suspended: 100,
  // High — near-immediate
  mention: 80,
  dm_received: 85,
  live_started: 75,
  stream_gift: 90,
  tip_received: 88,
  subscription_new: 85,
  // Medium — batched
  comment: 60,
  reply: 65,
  like_milestone: 55,
  follow: 50,
  community_post: 45,
  // Low — digest
  trending_content: 30,
  weekly_summary: 20,
  recommendation: 25,
  // Ambient — background
  system_update: 10,
  feature_announcement: 15
};
function computePriorityScore(type, actorReputation, userEngagementRate, timeSensitive) {
  const base = PRIORITY_WEIGHTS[type] ?? 40;
  const reputationBonus = actorReputation > 80 ? 10 : actorReputation > 50 ? 5 : 0;
  const engagementMultiplier = 1 + userEngagementRate * 0.2;
  const urgencyBonus = timeSensitive ? 15 : 0;
  const score = Math.min(100, Math.round((base + reputationBonus + urgencyBonus) * engagementMultiplier));
  let priority;
  if (score >= 90) priority = "critical";
  else if (score >= 70) priority = "high";
  else if (score >= 45) priority = "medium";
  else if (score >= 20) priority = "low";
  else priority = "ambient";
  return { score, priority };
}
function buildBatchKey(type, entityId) {
  const batchableTypes = ["like", "follow", "comment", "community_post", "recommendation"];
  if (!batchableTypes.includes(type)) return null;
  return entityId ? `${type}:${entityId}` : `${type}:global`;
}
var tableEnsured = false;
async function ensureNotifTable() {
  if (tableEnsured) return;
  const db2 = await getDb();
  if (!db2) return;
  await db2.execute(sql2.raw(`
    CREATE TABLE IF NOT EXISTS notification_intelligence (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      type VARCHAR(64) NOT NULL,
      title VARCHAR(255) NOT NULL,
      body TEXT NOT NULL,
      priority ENUM('critical','high','medium','low','ambient') NOT NULL DEFAULT 'medium',
      score INT NOT NULL DEFAULT 50,
      \`read\` TINYINT(1) NOT NULL DEFAULT 0,
      actor_id INT,
      entity_id INT,
      entity_type VARCHAR(64),
      batch_key VARCHAR(128),
      batch_count INT NOT NULL DEFAULT 1,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      read_at DATETIME,
      action_url VARCHAR(512),
      metadata JSON,
      INDEX idx_user_read (user_id, \`read\`),
      INDEX idx_user_priority (user_id, priority, created_at),
      INDEX idx_batch_key (user_id, batch_key)
    )
  `));
  tableEnsured = true;
}
async function insertNotifRaw(db2, userId, type, title, body, priority, score, actorId, entityId, entityType, actionUrl) {
  const batchKey = buildBatchKey(type, entityId);
  const esc = (s) => s ? `'${s.replace(/'/g, "''")}'` : "NULL";
  const num = (n) => n !== null ? String(n) : "NULL";
  if (batchKey) {
    const [existing] = await db2.execute(sql2.raw(
      `SELECT id, batch_count FROM notification_intelligence WHERE user_id=${userId} AND batch_key=${esc(batchKey)} AND \`read\`=0 ORDER BY created_at DESC LIMIT 1`
    ));
    const rows = Array.isArray(existing) ? existing : [existing];
    const row = rows[0];
    if (row && row.id) {
      const newCount = (row.batch_count ?? 1) + 1;
      const batchTitle = title.replace(/^1 /, `${newCount} `);
      await db2.execute(sql2.raw(
        `UPDATE notification_intelligence SET batch_count=${newCount}, title=${esc(batchTitle)}, score=GREATEST(score,${score}), created_at=NOW() WHERE id=${row.id}`
      ));
      return;
    }
  }
  await db2.execute(sql2.raw(
    `INSERT INTO notification_intelligence (user_id,type,title,body,priority,score,actor_id,entity_id,entity_type,batch_key,action_url) VALUES (${userId},${esc(type)},${esc(title)},${esc(body)},${esc(priority)},${score},${num(actorId)},${num(entityId)},${esc(entityType)},${esc(batchKey)},${esc(actionUrl)})`
  ));
}
var notificationIntelligenceRouter = router({
  /** Get smart-ranked notifications for the current user */
  getIntelligentFeed: protectedProcedure.input(z7.object({
    limit: z7.number().min(1).max(100).default(30),
    filter: z7.enum(["all", "unread", "critical", "high", "medium", "low"]).default("all"),
    offset: z7.number().default(0)
  })).query(async ({ ctx, input }) => {
    await ensureNotifTable();
    const db2 = await getDb();
    if (!db2) return { notifications: [], total: 0, unreadCount: 0 };
    const { limit, filter, offset } = input;
    let whereExtra = "";
    if (filter === "unread") whereExtra = " AND `read` = 0";
    else if (["critical", "high", "medium", "low"].includes(filter)) whereExtra = ` AND priority = '${filter}'`;
    const [rows] = await db2.execute(sql2.raw(
      `SELECT * FROM notification_intelligence WHERE user_id=${ctx.user.id}${whereExtra} ORDER BY score DESC, created_at DESC LIMIT ${limit} OFFSET ${offset}`
    ));
    const notifs = Array.isArray(rows) ? rows : [];
    const [countRows] = await db2.execute(sql2.raw(
      `SELECT COUNT(*) as total, SUM(\`read\`=0) as unread FROM notification_intelligence WHERE user_id=${ctx.user.id}`
    ));
    const counts = Array.isArray(countRows) ? countRows[0] : countRows;
    return {
      notifications: notifs.map((n) => ({
        id: n.id,
        type: n.type,
        title: n.title,
        body: n.body,
        priority: n.priority,
        score: n.score,
        read: !!n.read,
        actorId: n.actor_id,
        entityId: n.entity_id,
        entityType: n.entity_type,
        batchCount: n.batch_count ?? 1,
        createdAt: n.created_at,
        readAt: n.read_at,
        actionUrl: n.action_url
      })),
      total: Number(counts?.total ?? 0),
      unreadCount: Number(counts?.unread ?? 0)
    };
  }),
  /** Mark notification(s) as read */
  markRead: protectedProcedure.input(z7.object({
    ids: z7.array(z7.number()).optional(),
    all: z7.boolean().optional()
  })).mutation(async ({ ctx, input }) => {
    await ensureNotifTable();
    const db2 = await getDb();
    if (!db2) return { success: false };
    if (input.all) {
      await db2.execute(sql2.raw(
        `UPDATE notification_intelligence SET \`read\`=1, read_at=NOW() WHERE user_id=${ctx.user.id} AND \`read\`=0`
      ));
    } else if (input.ids && input.ids.length > 0) {
      const idList = input.ids.join(",");
      await db2.execute(sql2.raw(
        `UPDATE notification_intelligence SET \`read\`=1, read_at=NOW() WHERE id IN (${idList}) AND user_id=${ctx.user.id}`
      ));
    }
    return { success: true };
  }),
  /** Push a notification with intelligent priority scoring */
  pushNotification: protectedProcedure.input(z7.object({
    targetUserId: z7.number(),
    type: z7.string(),
    title: z7.string(),
    body: z7.string(),
    actorId: z7.number().optional(),
    entityId: z7.number().optional(),
    entityType: z7.string().optional(),
    actionUrl: z7.string().optional(),
    timeSensitive: z7.boolean().default(false)
  })).mutation(async ({ ctx: _ctx, input }) => {
    await ensureNotifTable();
    const db2 = await getDb();
    if (!db2) return { success: false, priority: "medium", score: 50 };
    const { score, priority } = computePriorityScore(
      input.type,
      50,
      // default actor reputation
      0.5,
      // default engagement rate
      input.timeSensitive
    );
    await insertNotifRaw(
      db2,
      input.targetUserId,
      input.type,
      input.title,
      input.body,
      priority,
      score,
      input.actorId ?? null,
      input.entityId ?? null,
      input.entityType ?? null,
      input.actionUrl ?? null
    );
    return { success: true, priority, score };
  }),
  /** Get notification preferences */
  getPreferences: protectedProcedure.query(async ({ ctx: _ctx }) => {
    return {
      minPriority: "medium",
      batchingEnabled: true,
      digestMode: false,
      quietHoursStart: 22,
      quietHoursEnd: 8,
      channels: { inApp: true, push: true, email: false, sms: false },
      typeOverrides: {}
    };
  }),
  /** AI-powered notification summary */
  getAISummary: protectedProcedure.query(async ({ ctx }) => {
    await ensureNotifTable();
    const db2 = await getDb();
    if (!db2) return { summary: "You're all caught up!", highlights: [] };
    const [rows] = await db2.execute(sql2.raw(
      `SELECT type, COUNT(*) as cnt, MAX(score) as max_score FROM notification_intelligence WHERE user_id=${ctx.user.id} AND \`read\`=0 GROUP BY type ORDER BY max_score DESC LIMIT 10`
    ));
    const data = Array.isArray(rows) ? rows : [];
    if (!data || data.length === 0) {
      return { summary: "You're all caught up! No unread notifications.", highlights: [] };
    }
    const summaryInput = data.map((r) => `${r.cnt}x ${r.type}`).join(", ");
    const response = await invokeLLM({
      messages: [
        { role: "system", content: "You are a notification assistant. Summarize unread notifications in 1-2 sentences, friendly and concise." },
        { role: "user", content: `Unread notifications: ${summaryInput}. Give a brief summary.` }
      ]
    });
    const rawSummary = response.choices?.[0]?.message?.content;
    const summary = typeof rawSummary === "string" ? rawSummary : "You have new activity waiting for you.";
    return {
      summary,
      highlights: data.slice(0, 5).map((r) => ({ type: r.type, count: Number(r.cnt) }))
    };
  }),
  /** Get notification analytics */
  getAnalytics: protectedProcedure.query(async ({ ctx }) => {
    await ensureNotifTable();
    const db2 = await getDb();
    if (!db2) return { byPriority: [] };
    const [rows] = await db2.execute(sql2.raw(
      `SELECT 
        priority,
        COUNT(*) as total,
        SUM(\`read\`=1) as read_count,
        AVG(score) as avg_score,
        AVG(CASE WHEN read_at IS NOT NULL THEN TIMESTAMPDIFF(SECOND, created_at, read_at) END) as avg_read_time_secs
      FROM notification_intelligence 
      WHERE user_id=${ctx.user.id} AND created_at > DATE_SUB(NOW(), INTERVAL 30 DAY)
      GROUP BY priority`
    ));
    const data = Array.isArray(rows) ? rows : [];
    return {
      byPriority: data.map((r) => ({
        priority: r.priority,
        total: Number(r.total),
        readCount: Number(r.read_count),
        readRate: r.total > 0 ? Math.round(r.read_count / r.total * 100) : 0,
        avgScore: Math.round(Number(r.avg_score)),
        avgReadTimeSecs: r.avg_read_time_secs ? Math.round(Number(r.avg_read_time_secs)) : null
      }))
    };
  })
});

// server/compliance-router.ts
import { z as z8 } from "zod";
init_db();
init_llm();
import { sql as sql3 } from "drizzle-orm";
var tableEnsured2 = false;
async function ensureComplianceTables() {
  if (tableEnsured2) return;
  const db2 = await getDb();
  if (!db2) return;
  await db2.execute(sql3.raw(`
    CREATE TABLE IF NOT EXISTS kyc_records (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL UNIQUE,
      status ENUM('not_started','pending','in_review','approved','rejected','expired') NOT NULL DEFAULT 'not_started',
      level ENUM('basic','standard','enhanced') NOT NULL DEFAULT 'basic',
      first_name VARCHAR(128),
      last_name VARCHAR(128),
      date_of_birth DATE,
      country VARCHAR(64),
      document_type VARCHAR(64),
      document_number VARCHAR(128),
      document_url VARCHAR(512),
      selfie_url VARCHAR(512),
      risk_score INT DEFAULT 0,
      rejection_reason TEXT,
      submitted_at DATETIME,
      reviewed_at DATETIME,
      expires_at DATETIME,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
      INDEX idx_status (status),
      INDEX idx_user (user_id)
    )
  `));
  await db2.execute(sql3.raw(`
    CREATE TABLE IF NOT EXISTS consent_records (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      consent_type VARCHAR(64) NOT NULL,
      granted TINYINT(1) NOT NULL DEFAULT 0,
      version VARCHAR(32) NOT NULL DEFAULT '1.0',
      ip_address VARCHAR(64),
      user_agent TEXT,
      granted_at DATETIME,
      revoked_at DATETIME,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      UNIQUE KEY uq_user_consent (user_id, consent_type),
      INDEX idx_user_id (user_id)
    )
  `));
  await db2.execute(sql3.raw(`
    CREATE TABLE IF NOT EXISTS data_deletion_requests (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      request_type ENUM('full_deletion','partial_deletion','data_export','correction') NOT NULL,
      status ENUM('pending','processing','completed','rejected') NOT NULL DEFAULT 'pending',
      reason TEXT,
      scope JSON,
      scheduled_at DATETIME,
      completed_at DATETIME,
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      INDEX idx_user (user_id),
      INDEX idx_status (status)
    )
  `));
  await db2.execute(sql3.raw(`
    CREATE TABLE IF NOT EXISTS compliance_audit_log (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT,
      action VARCHAR(128) NOT NULL,
      entity_type VARCHAR(64),
      entity_id INT,
      details JSON,
      ip_address VARCHAR(64),
      created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
      INDEX idx_user (user_id),
      INDEX idx_action (action),
      INDEX idx_created (created_at)
    )
  `));
  tableEnsured2 = true;
}
async function logComplianceAction(db2, userId, action, entityType, entityId, details) {
  const detailsJson = JSON.stringify(details).replace(/'/g, "''");
  await db2.execute(sql3.raw(
    `INSERT INTO compliance_audit_log (user_id, action, entity_type, entity_id, details) VALUES (${userId ?? "NULL"}, '${action}', ${entityType ? `'${entityType}'` : "NULL"}, ${entityId ?? "NULL"}, '${detailsJson}')`
  ));
}
var complianceRouter = router({
  // ── KYC ──────────────────────────────────────────────────────────────────
  /** Get current user's KYC status */
  getKYCStatus: protectedProcedure.query(async ({ ctx }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) return { status: "not_started", level: "basic", record: null };
    const [rows] = await db2.execute(sql3.raw(
      `SELECT * FROM kyc_records WHERE user_id=${ctx.user.id} LIMIT 1`
    ));
    const data = Array.isArray(rows) ? rows : [];
    const record = data[0] ?? null;
    return {
      status: record?.status ?? "not_started",
      level: record?.level ?? "basic",
      riskScore: record?.risk_score ?? 0,
      submittedAt: record?.submitted_at ?? null,
      reviewedAt: record?.reviewed_at ?? null,
      expiresAt: record?.expires_at ?? null,
      rejectionReason: record?.rejection_reason ?? null,
      record: record ? {
        firstName: record.first_name,
        lastName: record.last_name,
        country: record.country,
        documentType: record.document_type
      } : null
    };
  }),
  /** Submit KYC application */
  submitKYC: protectedProcedure.input(z8.object({
    firstName: z8.string().min(1).max(128),
    lastName: z8.string().min(1).max(128),
    dateOfBirth: z8.string().regex(/^\d{4}-\d{2}-\d{2}$/),
    country: z8.string().min(2).max(64),
    documentType: z8.enum(["passport", "national_id", "drivers_license", "residence_permit"]),
    documentNumber: z8.string().min(1).max(128),
    level: z8.enum(["basic", "standard", "enhanced"]).default("basic")
  })).mutation(async ({ ctx, input }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) throw new Error("Database unavailable");
    const response = await invokeLLM({
      messages: [
        { role: "system", content: "You are a KYC risk assessment AI. Return a JSON object with: riskScore (0-100, where 0=low risk, 100=high risk) and flags (array of strings). Be conservative." },
        { role: "user", content: `KYC submission: country=${input.country}, documentType=${input.documentType}, level=${input.level}. Assess risk.` }
      ],
      response_format: {
        type: "json_schema",
        json_schema: {
          name: "kyc_risk",
          strict: true,
          schema: {
            type: "object",
            properties: {
              riskScore: { type: "integer" },
              flags: { type: "array", items: { type: "string" } }
            },
            required: ["riskScore", "flags"],
            additionalProperties: false
          }
        }
      }
    });
    let riskScore = 20;
    try {
      const rawContent = response.choices?.[0]?.message?.content;
      const parsed = JSON.parse(typeof rawContent === "string" ? rawContent : "{}");
      riskScore = Math.min(100, Math.max(0, parsed.riskScore ?? 20));
    } catch {
    }
    const status = riskScore > 70 ? "in_review" : "pending";
    const expiresAt = new Date(Date.now() + 365 * 24 * 60 * 60 * 1e3);
    await db2.execute(sql3.raw(`
        INSERT INTO kyc_records (user_id, status, level, first_name, last_name, date_of_birth, country, document_type, document_number, risk_score, submitted_at, expires_at)
        VALUES (${ctx.user.id}, '${status}', '${input.level}', '${input.firstName.replace(/'/g, "''")}', '${input.lastName.replace(/'/g, "''")}', '${input.dateOfBirth}', '${input.country.replace(/'/g, "''")}', '${input.documentType}', '${input.documentNumber.replace(/'/g, "''")}', ${riskScore}, NOW(), '${expiresAt.toISOString().slice(0, 19)}')
        ON DUPLICATE KEY UPDATE status='${status}', level='${input.level}', first_name='${input.firstName.replace(/'/g, "''")}', last_name='${input.lastName.replace(/'/g, "''")}', date_of_birth='${input.dateOfBirth}', country='${input.country.replace(/'/g, "''")}', document_type='${input.documentType}', document_number='${input.documentNumber.replace(/'/g, "''")}', risk_score=${riskScore}, submitted_at=NOW(), expires_at='${expiresAt.toISOString().slice(0, 19)}', updated_at=NOW()
      `));
    await logComplianceAction(db2, ctx.user.id, "kyc_submitted", "kyc", null, { level: input.level, country: input.country, riskScore });
    return { success: true, status, riskScore };
  }),
  // ── GDPR / Consent ────────────────────────────────────────────────────────
  /** Get all consent records for current user */
  getConsents: protectedProcedure.query(async ({ ctx }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) return { consents: [] };
    const [rows] = await db2.execute(sql3.raw(
      `SELECT * FROM consent_records WHERE user_id=${ctx.user.id}`
    ));
    const data = Array.isArray(rows) ? rows : [];
    const consentTypes = ["terms", "privacy", "marketing", "analytics", "cookies", "age_verification"];
    const existing = new Map(data.map((r) => [r.consent_type, r]));
    return {
      consents: consentTypes.map((type) => {
        const r = existing.get(type);
        return {
          type,
          granted: r ? !!r.granted : false,
          version: r?.version ?? "1.0",
          grantedAt: r?.granted_at ?? null,
          revokedAt: r?.revoked_at ?? null,
          required: ["terms", "privacy", "age_verification"].includes(type)
        };
      })
    };
  }),
  /** Update consent for a specific type */
  updateConsent: protectedProcedure.input(z8.object({
    consentType: z8.enum(["terms", "privacy", "marketing", "analytics", "cookies", "age_verification"]),
    granted: z8.boolean(),
    version: z8.string().default("1.0")
  })).mutation(async ({ ctx, input }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) throw new Error("Database unavailable");
    const grantedAt = input.granted ? "NOW()" : "NULL";
    const revokedAt = input.granted ? "NULL" : "NOW()";
    await db2.execute(sql3.raw(`
        INSERT INTO consent_records (user_id, consent_type, granted, version, granted_at, revoked_at)
        VALUES (${ctx.user.id}, '${input.consentType}', ${input.granted ? 1 : 0}, '${input.version}', ${grantedAt}, ${revokedAt})
        ON DUPLICATE KEY UPDATE granted=${input.granted ? 1 : 0}, version='${input.version}', granted_at=${grantedAt}, revoked_at=${revokedAt}
      `));
    await logComplianceAction(db2, ctx.user.id, input.granted ? "consent_granted" : "consent_revoked", "consent", null, { consentType: input.consentType, version: input.version });
    return { success: true };
  }),
  // ── Data Rights (GDPR Article 17/20) ─────────────────────────────────────
  /** Request data export (GDPR Article 20 - Data Portability) */
  requestDataExport: protectedProcedure.mutation(async ({ ctx }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) throw new Error("Database unavailable");
    const scheduledAt = new Date(Date.now() + 24 * 60 * 60 * 1e3);
    await db2.execute(sql3.raw(`
      INSERT INTO data_deletion_requests (user_id, request_type, status, scheduled_at)
      VALUES (${ctx.user.id}, 'data_export', 'pending', '${scheduledAt.toISOString().slice(0, 19)}')
    `));
    await logComplianceAction(db2, ctx.user.id, "data_export_requested", "user", ctx.user.id, {});
    return { success: true, scheduledAt, message: "Your data export will be ready within 24 hours." };
  }),
  /** Request account deletion (GDPR Article 17 - Right to Erasure) */
  requestDeletion: protectedProcedure.input(z8.object({
    type: z8.enum(["full_deletion", "partial_deletion"]),
    reason: z8.string().max(500).optional(),
    scope: z8.array(z8.string()).optional()
  })).mutation(async ({ ctx, input }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) throw new Error("Database unavailable");
    const scheduledAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1e3);
    const scopeJson = input.scope ? JSON.stringify(input.scope).replace(/'/g, "''") : "NULL";
    const reason = input.reason ? `'${input.reason.replace(/'/g, "''")}'` : "NULL";
    await db2.execute(sql3.raw(`
        INSERT INTO data_deletion_requests (user_id, request_type, status, reason, scope, scheduled_at)
        VALUES (${ctx.user.id}, '${input.type}', 'pending', ${reason}, ${scopeJson !== "NULL" ? `'${scopeJson}'` : "NULL"}, '${scheduledAt.toISOString().slice(0, 19)}')
      `));
    await logComplianceAction(db2, ctx.user.id, "deletion_requested", "user", ctx.user.id, { type: input.type, reason: input.reason });
    return {
      success: true,
      scheduledAt,
      gracePeriodDays: 30,
      message: "Your deletion request has been submitted. You have 30 days to cancel this request."
    };
  }),
  /** Get pending data requests */
  getDataRequests: protectedProcedure.query(async ({ ctx }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) return { requests: [] };
    const [rows] = await db2.execute(sql3.raw(
      `SELECT * FROM data_deletion_requests WHERE user_id=${ctx.user.id} ORDER BY created_at DESC LIMIT 20`
    ));
    const data = Array.isArray(rows) ? rows : [];
    return {
      requests: data.map((r) => ({
        id: r.id,
        type: r.request_type,
        status: r.status,
        reason: r.reason,
        scheduledAt: r.scheduled_at,
        completedAt: r.completed_at,
        createdAt: r.created_at
      }))
    };
  }),
  /** Cancel a pending deletion request */
  cancelDeletionRequest: protectedProcedure.input(z8.object({ requestId: z8.number() })).mutation(async ({ ctx, input }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) throw new Error("Database unavailable");
    await db2.execute(sql3.raw(
      `UPDATE data_deletion_requests SET status='rejected' WHERE id=${input.requestId} AND user_id=${ctx.user.id} AND status='pending'`
    ));
    await logComplianceAction(db2, ctx.user.id, "deletion_cancelled", "request", input.requestId, {});
    return { success: true };
  }),
  /** Get compliance audit log for current user */
  getAuditLog: protectedProcedure.input(z8.object({ limit: z8.number().default(50) })).query(async ({ ctx, input }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) return { events: [] };
    const [rows] = await db2.execute(sql3.raw(
      `SELECT * FROM compliance_audit_log WHERE user_id=${ctx.user.id} ORDER BY created_at DESC LIMIT ${input.limit}`
    ));
    const data = Array.isArray(rows) ? rows : [];
    return {
      events: data.map((r) => ({
        id: r.id,
        action: r.action,
        entityType: r.entity_type,
        entityId: r.entity_id,
        details: r.details,
        createdAt: r.created_at
      }))
    };
  }),
  /** Get compliance summary / health score */
  getComplianceSummary: protectedProcedure.query(async ({ ctx }) => {
    await ensureComplianceTables();
    const db2 = await getDb();
    if (!db2) return { score: 0, issues: [], kycStatus: "not_started" };
    const [kycRows] = await db2.execute(sql3.raw(
      `SELECT status, level FROM kyc_records WHERE user_id=${ctx.user.id} LIMIT 1`
    ));
    const kycData = Array.isArray(kycRows) ? kycRows : [];
    const kyc = kycData[0];
    const [consentRows] = await db2.execute(sql3.raw(
      `SELECT consent_type, granted FROM consent_records WHERE user_id=${ctx.user.id}`
    ));
    const consentData = Array.isArray(consentRows) ? consentRows : [];
    const consents = new Map(consentData.map((r) => [r.consent_type, !!r.granted]));
    const issues = [];
    let score = 100;
    if (!kyc || kyc.status === "not_started") {
      issues.push("KYC verification not started");
      score -= 30;
    } else if (kyc.status === "rejected") {
      issues.push("KYC verification rejected");
      score -= 25;
    } else if (kyc.status === "expired") {
      issues.push("KYC verification expired");
      score -= 20;
    }
    if (!consents.get("terms")) {
      issues.push("Terms of Service not accepted");
      score -= 20;
    }
    if (!consents.get("privacy")) {
      issues.push("Privacy Policy not accepted");
      score -= 15;
    }
    if (!consents.get("age_verification")) {
      issues.push("Age verification not completed");
      score -= 10;
    }
    return {
      score: Math.max(0, score),
      issues,
      kycStatus: kyc?.status ?? "not_started",
      kycLevel: kyc?.level ?? "basic",
      consentsGranted: consentData.filter((r) => r.granted).length,
      consentsTotal: 6
    };
  })
});

