      educationEnabled: input.educationEnabled !== void 0 ? input.educationEnabled ? 1 : 0 : void 0,
      developerToolsEnabled: input.developerToolsEnabled !== void 0 ? input.developerToolsEnabled ? 1 : 0 : void 0
