var TournamentService = class {
  async createTournament(creatorId, config) {
    const db2 = await getDb();
    if (!db2) return null;
    const prizePool = config.entryFee * config.maxParticipants * 0.9;
    const defaultDistribution = [
      { place: 1, percent: 50 },
      { place: 2, percent: 30 },
      { place: 3, percent: 15 },
      { place: 4, percent: 5 }
    ];
    if (config.entryFee > 0) {
      await db2.insert(transactions).values({
        userId: creatorId,
        type: "purchase",
        token: "SKY444",
        amount: String(config.entryFee),
        status: "confirmed",
        metadata: { type: "tournament_creation", name: config.name }
      });
    }
    return {
      id: Date.now(),
      name: config.name,
      game: config.game,
      type: config.type,
      status: "registration",
      maxParticipants: config.maxParticipants,
      currentParticipants: 0,
      entryFee: config.entryFee,
      prizePool,
      prizeDistribution: config.prizeDistribution || defaultDistribution,
      startTime: config.startTime,
      rules: config.rules || ["No cheating", "Best of 3", "Standard rules apply"]
    };
  }
  async joinTournament(tournamentId, userId) {
    const db2 = await getDb();
    if (!db2) return false;
    const [balance] = await db2.select({ balance: tokenBalances.balance }).from(tokenBalances).where(
      and13(
        eq18(tokenBalances.userId, userId),
        eq18(tokenBalances.token, "SKY444")
      )
    );
    return !!balance;
  }
  generateBracket(participants, type) {
    const matches = [];
    const totalRounds = Math.ceil(Math.log2(participants.length));
    if (type === "single_elimination" || type === "double_elimination") {
      let matchNum = 1;
      for (let round = 1; round <= totalRounds; round++) {
        const matchesInRound = Math.pow(2, totalRounds - round);
        for (let i = 0; i < matchesInRound; i++) {
          const match = {
            id: matchNum,
            round,
            matchNumber: i + 1,
            status: "pending"
          };
          if (round === 1) {
            const idx = i * 2;
            match.player1Id = participants[idx];
            match.player2Id = participants[idx + 1];
          }
          matches.push(match);
          matchNum++;
        }
      }
    } else if (type === "round_robin") {
      let matchNum = 1;
      for (let i = 0; i < participants.length; i++) {
        for (let j = i + 1; j < participants.length; j++) {
          matches.push({
            id: matchNum++,
            round: 1,
            matchNumber: matchNum,
            player1Id: participants[i],
            player2Id: participants[j],
            status: "pending"
          });
        }
      }
    }
    return matches;
  }
  async reportMatch(matchId, winnerId, score1, score2) {
    return true;
  }
  async getTournamentStandings(tournamentId) {
    return [];
  }
  async distributePrizes(tournamentId) {
    return [];
  }
};
