var SeasonPassService = class {
  async getCurrentSeason() {
    const db2 = await getDb();
    if (!db2) return null;
    const [season] = await db2.select().from(seasons).where(eq18(seasons.status, "active")).limit(1);
    if (!season) return null;
    const maxLevel = 100;
    const tiers = [];
    for (let i = 1; i <= maxLevel; i++) {
      tiers.push({
        level: i,
        xpRequired: i * 1e3 + (i > 50 ? (i - 50) * 500 : 0),
        freeReward: i % 5 === 0 ? { type: "tokens", amount: i * 10, name: `${i * 10} SKY444` } : void 0,
        premiumReward: i % 3 === 0 ? { type: "xp", amount: i * 50, name: `${i * 50} Bonus XP` } : void 0,
        isUnlocked: false
      });
    }
    return {
      id: season.id,
      seasonNumber: season.number,
      name: season.name,
      theme: "default",
      startDate: season.startsAt,
      endDate: season.endsAt,
      maxLevel,
      tiers,
      currentXp: 0,
      currentLevel: 0,
      isPremium: false
    };
  }
  async getUserSeasonProgress(userId) {
    const db2 = await getDb();
    if (!db2) return { level: 0, xp: 0, isPremium: false, claimedRewards: [] };
    const [user] = await db2.select({ xp: users.xp, level: users.level }).from(users).where(eq18(users.id, userId));
    return {
      level: user?.level || 0,
      xp: user?.xp || 0,
      isPremium: false,
      claimedRewards: []
    };
  }
  async addSeasonXp(userId, amount, source) {
    const db2 = await getDb();
    if (!db2) return { newXp: 0, newLevel: 0, leveledUp: false };
    const [user] = await db2.select({ xp: users.xp, level: users.level }).from(users).where(eq18(users.id, userId));
    if (!user) return { newXp: 0, newLevel: 0, leveledUp: false };
    const newXp = (user.xp || 0) + amount;
    const xpPerLevel = 1e3;
    const newLevel = Math.floor(newXp / xpPerLevel);
    const leveledUp = newLevel > (user.level || 0);
    await db2.update(users).set({
      xp: newXp,
      level: newLevel
    }).where(eq18(users.id, userId));
    if (leveledUp) {
      await db2.insert(notifications).values({
        userId,
        type: "system",
        title: `Level Up! You're now level ${newLevel}`,
        message: `You earned ${amount} XP from ${source}`,
        targetType: "level",
        targetId: newLevel
      });
    }
    return { newXp, newLevel, leveledUp };
  }
  async purchasePremiumPass(userId) {
    const db2 = await getDb();
    if (!db2) return false;
    const PREMIUM_COST = 999;
    const [balance] = await db2.select({ balance: tokenBalances.balance }).from(tokenBalances).where(
      and13(
        eq18(tokenBalances.userId, userId),
        eq18(tokenBalances.token, "SKY444")
      )
    );
    if (!balance || parseFloat(String(balance.balance)) < PREMIUM_COST) return false;
    await db2.update(tokenBalances).set({
      balance: sql17`${tokenBalances.balance} - ${PREMIUM_COST}`
    }).where(
      and13(
        eq18(tokenBalances.userId, userId),
        eq18(tokenBalances.token, "SKY444")
      )
    );
    return true;
  }
};
