var AntiCheatService = class {
  async analyzePlayer(userId) {
    const db2 = await getDb();
    if (!db2) return { score: 100, flags: [], isSuspicious: false };
    const flags = [];
    let score = 100;
    const [tradeStats] = await db2.select({
      count: sql17`COUNT(*)`,
      avgInterval: sql17`AVG(TIMESTAMPDIFF(SECOND, LAG(createdAt) OVER (ORDER BY createdAt), createdAt))`
    }).from(transactions).where(
      and13(
        eq18(transactions.userId, userId),
        gte12(transactions.createdAt, new Date(Date.now() - 60 * 60 * 1e3))
      )
    );
    if (tradeStats && tradeStats.count > 100) {
      flags.push("high_frequency_trading");
      score -= 20;
    }
    const [user] = await db2.select({ xp: users.xp, createdAt: users.createdAt }).from(users).where(eq18(users.id, userId));
    if (user) {
      const daysSinceCreation = (Date.now() - new Date(user.createdAt).getTime()) / (24 * 60 * 60 * 1e3);
      const xpPerDay = (user.xp || 0) / Math.max(1, daysSinceCreation);
      if (xpPerDay > 1e4) {
        flags.push("abnormal_xp_gain");
        score -= 30;
      }
    }
    return {
      score: Math.max(0, score),
      flags,
      isSuspicious: score < 60
    };
  }
};
