var RevenueSplitCalculator = class {
  constructor() {
    this.PLATFORM_FEE_RATE = 0.1;
    // 10% platform fee
    this.REFERRAL_BONUS_RATE = 0.05;
    // 5% referral bonus
    this.TAX_WITHHOLDING_RATE = 0;
  }
  // 0% default (creator handles own taxes)
  calculate(grossAmount, hasReferrer = false) {
    const platformFee = grossAmount * this.PLATFORM_FEE_RATE;
    const referralBonus = hasReferrer ? grossAmount * this.REFERRAL_BONUS_RATE : 0;
    const taxWithholding = grossAmount * this.TAX_WITHHOLDING_RATE;
    const netCreatorEarnings = grossAmount - platformFee - referralBonus - taxWithholding;
    return {
      creatorShare: netCreatorEarnings / grossAmount,
      platformFee,
      referralBonus,
      taxWithholding,
      netCreatorEarnings
    };
  }
  calculateBulk(amounts) {
    const splits = amounts.map((a) => this.calculate(a));
    return {
      total: splits.reduce((sum4, s) => sum4 + s.netCreatorEarnings, 0),
      splits
    };
  }
};
