var PriceOracle = class {
  // $0.05 per SKY444
  constructor() {
    this.priceHistory = [];
    this.currentPrice = 0.05;
    for (let d = 30; d >= 0; d--) {
      const basePrice = 0.05;
      const volatility = 0.02;
      const trend = 1e-3 * (30 - d);
      const noise = (Math.random() - 0.5) * volatility;
      const price = basePrice + trend + noise;
      this.priceHistory.push({
        timestamp: new Date(Date.now() - d * 24 * 60 * 60 * 1e3),
        open: price - Math.random() * 5e-3,
        high: price + Math.random() * 0.01,
        low: price - Math.random() * 0.01,
        close: price,
        volume: 5e4 + Math.random() * 1e5
      });
    }
    this.currentPrice = this.priceHistory[this.priceHistory.length - 1].close;
  }
  getCurrentPrice() {
    return this.currentPrice;
  }
  getTWAP(periods = 24) {
    const recent = this.priceHistory.slice(-periods);
    return recent.reduce((sum4, p) => sum4 + p.close, 0) / recent.length;
  }
  getVWAP(periods = 24) {
    const recent = this.priceHistory.slice(-periods);
    const totalVolume = recent.reduce((sum4, p) => sum4 + p.volume, 0);
    const volumeWeightedPrice = recent.reduce((sum4, p) => sum4 + p.close * p.volume, 0);
    return totalVolume > 0 ? volumeWeightedPrice / totalVolume : this.currentPrice;
  }
  getPriceHistory(days = 30) {
    return this.priceHistory.slice(-days);
  }
  get24hChange() {
    if (this.priceHistory.length < 2) return { amount: 0, percent: 0 };
    const yesterday = this.priceHistory[this.priceHistory.length - 2].close;
    const today = this.currentPrice;
    return {
      amount: today - yesterday,
      percent: (today - yesterday) / yesterday * 100
    };
  }
  getMarketCap() {
    return this.currentPrice * 1e9;
  }
};
