var REFEREE_BONUS_PERCENT = 3;
async function ensureIcoTables() {
  const db2 = await getDb();
  if (!db2) return;
  await db2.execute(`
    CREATE TABLE IF NOT EXISTS ico_purchases (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      tier_id VARCHAR(20) NOT NULL,
      usd_amount DECIMAL(18,2) NOT NULL,
      token_amount DECIMAL(18,6) NOT NULL,
      bonus_tokens DECIMAL(18,6) NOT NULL DEFAULT 0,
      referral_code VARCHAR(20),
      stripe_session_id VARCHAR(255),
      stripe_payment_intent VARCHAR(255),
      status ENUM('pending','paid','failed','refunded') DEFAULT 'pending',
      vesting_start BIGINT,
      vesting_end BIGINT,
      cliff_end BIGINT,
      tge_released DECIMAL(18,6) DEFAULT 0,
      tokens_released DECIMAL(18,6) DEFAULT 0,
      created_at BIGINT NOT NULL,
      updated_at BIGINT NOT NULL
    )
  `);
  await db2.execute(`
    CREATE TABLE IF NOT EXISTS ico_referral_codes (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      code VARCHAR(20) NOT NULL UNIQUE,
      uses INT DEFAULT 0,
      total_bonus_earned DECIMAL(18,6) DEFAULT 0,
      created_at BIGINT NOT NULL
    )
  `);
  await db2.execute(`
    CREATE TABLE IF NOT EXISTS ico_whitelist (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      tier_id VARCHAR(20) NOT NULL,
      approved TINYINT DEFAULT 0,
      kyc_status ENUM('pending','approved','rejected') DEFAULT 'pending',
      created_at BIGINT NOT NULL
    )
  `);
}
var icoRouter = router({
  // Get all ICO tiers with live raised amounts
  getTiers: publicProcedure.query(async () => {
    await ensureIcoTables();
    const db2 = await getDb();
    const raised = {};
    if (db2) {
      for (const tier of ICO_TIERS) {
        try {
          const rows = await db2.execute(
            `SELECT COALESCE(SUM(usd_amount), 0) as total FROM ico_purchases WHERE tier_id = '${tier.id}' AND status = 'paid'`
          );
          raised[tier.id] = parseFloat(rows.rows?.[0]?.total ?? "0");
        } catch {
          raised[tier.id] = 0;
        }
      }
    }
    return ICO_TIERS.map((tier) => ({
      ...tier,
      raisedUSD: raised[tier.id] ?? 0,
      raisedTokens: (raised[tier.id] ?? 0) / tier.priceUSD,
      percentFilled: Math.min(100, (raised[tier.id] ?? 0) / (tier.allocation * tier.priceUSD) * 100)
    }));
  }),
  // Get live ICO stats
  getStats: publicProcedure.query(async () => {
    await ensureIcoTables();
    const db2 = await getDb();
    if (!db2) return { totalRaisedUSD: 0, totalParticipants: 0, totalTokensSold: 0, activeTier: "presale" };
    try {
      const rows = await db2.execute(
        `SELECT COALESCE(SUM(usd_amount),0) as total_usd, COUNT(DISTINCT user_id) as participants, COALESCE(SUM(token_amount + bonus_tokens),0) as total_tokens FROM ico_purchases WHERE status = 'paid'`
      );
      const row = rows.rows?.[0] ?? {};
      return {
        totalRaisedUSD: parseFloat(row.total_usd ?? "0"),
        totalParticipants: parseInt(row.participants ?? "0"),
        totalTokensSold: parseFloat(row.total_tokens ?? "0"),
        activeTier: "presale"
      };
    } catch {
      return { totalRaisedUSD: 0, totalParticipants: 0, totalTokensSold: 0, activeTier: "presale" };
    }
  }),
  // Get or create referral code for current user
  getMyReferralCode: protectedProcedure.query(async ({ ctx }) => {
    await ensureIcoTables();
    const db2 = await getDb();
    if (!db2) return { code: "", uses: 0, totalBonusEarned: 0 };
    try {
      const existing = await db2.execute(
        `SELECT code, uses, total_bonus_earned FROM ico_referral_codes WHERE user_id = ${ctx.user.id} LIMIT 1`
      );
      if (existing.rows?.length > 0) {
        const r = existing.rows[0];
        return { code: r.code, uses: r.uses, totalBonusEarned: parseFloat(r.total_bonus_earned ?? "0") };
      }
      const code = `SKY${ctx.user.id.toString(36).toUpperCase()}${Math.random().toString(36).slice(2, 5).toUpperCase()}`;
      await db2.execute(
        `INSERT INTO ico_referral_codes (user_id, code, uses, total_bonus_earned, created_at) VALUES (${ctx.user.id}, '${code}', 0, 0, ${Date.now()})`
      );
      return { code, uses: 0, totalBonusEarned: 0 };
    } catch {
      return { code: "", uses: 0, totalBonusEarned: 0 };
    }
  }),
  // Get my purchase history and vesting schedule
  getMyPurchases: protectedProcedure.query(async ({ ctx }) => {
    await ensureIcoTables();
    const db2 = await getDb();
    if (!db2) return [];
    try {
      const rows = await db2.execute(
        `SELECT * FROM ico_purchases WHERE user_id = ${ctx.user.id} ORDER BY created_at DESC`
      );
      return (rows.rows ?? []).map((r) => ({
        id: r.id,
        tierId: r.tier_id,
        usdAmount: parseFloat(r.usd_amount ?? "0"),
        tokenAmount: parseFloat(r.token_amount ?? "0"),
        bonusTokens: parseFloat(r.bonus_tokens ?? "0"),
        totalTokens: parseFloat(r.token_amount ?? "0") + parseFloat(r.bonus_tokens ?? "0"),
        status: r.status,
        vestingStart: r.vesting_start,
        vestingEnd: r.vesting_end,
        cliffEnd: r.cliff_end,
        tgeReleased: parseFloat(r.tge_released ?? "0"),
        tokensReleased: parseFloat(r.tokens_released ?? "0"),
        createdAt: r.created_at,
        // Compute claimable
        claimableNow: computeClaimable(r)
      }));
    } catch {
      return [];
    }
  }),
  // Create Stripe checkout session for ICO purchase
  createCheckout: protectedProcedure.input(z27.object({
    tierId: z27.string(),
    usdAmount: z27.number().min(10).max(1e5),
    referralCode: z27.string().optional(),
    origin: z27.string()
  })).mutation(async ({ ctx, input }) => {
    await ensureIcoTables();
    const tier = ICO_TIERS.find((t2) => t2.id === input.tierId);
    if (!tier) throw new Error("Invalid tier");
    if (tier.status === "closed") throw new Error("This tier is closed");
    if (input.usdAmount < tier.minPurchaseUSD) throw new Error(`Minimum purchase is $${tier.minPurchaseUSD}`);
    if (input.usdAmount > tier.maxPurchaseUSD) throw new Error(`Maximum purchase is $${tier.maxPurchaseUSD}`);
    const db2 = await getDb();
    if (!db2) throw new Error("Database unavailable");
    let referralUserId = null;
    let refereeBonus = 0;
    if (input.referralCode) {
      try {
        const refRows = await db2.execute(
          `SELECT user_id FROM ico_referral_codes WHERE code = '${input.referralCode}' LIMIT 1`
        );
        if (refRows.rows?.length > 0) {
          referralUserId = refRows.rows[0].user_id;
          refereeBonus = input.usdAmount / tier.priceUSD * (REFEREE_BONUS_PERCENT / 100);
        }
      } catch {
      }
    }
    const baseTokens = input.usdAmount / tier.priceUSD;
    const bonusTokens = baseTokens * tier.bonus / 100 + refereeBonus;
    const now = Date.now();
    const vestingStart = now;
    const cliffEnd = now + tier.cliffMonths * 30 * 24 * 60 * 60 * 1e3;
    const vestingEnd = now + tier.vestingMonths * 30 * 24 * 60 * 60 * 1e3;
    const tgeReleased = baseTokens * (tier.tgePercent / 100);
    const insertResult = await db2.execute(
      `INSERT INTO ico_purchases (user_id, tier_id, usd_amount, token_amount, bonus_tokens, referral_code, status, vesting_start, vesting_end, cliff_end, tge_released, tokens_released, created_at, updated_at)
         VALUES (${ctx.user.id}, '${tier.id}', ${input.usdAmount}, ${baseTokens}, ${bonusTokens}, ${input.referralCode ? `'${input.referralCode}'` : "NULL"}, 'pending', ${vestingStart}, ${vestingEnd}, ${cliffEnd}, ${tgeReleased}, 0, ${now}, ${now})`
    );
    const purchaseId = insertResult.insertId ?? 0;
    try {
      const stripeModule = await Promise.resolve().then(() => (init_stripe_skycoin(), stripe_skycoin_exports));
      const session = await stripeModule.createCheckoutSession(
        purchaseId,
        ctx.user.id,
        input.usdAmount,
        `${input.origin}/ico?success=1&purchase=${purchaseId}`,
        `${input.origin}/ico?cancelled=1`
      );
      if (session?.url) {
        await db2.execute(
          `UPDATE ico_purchases SET stripe_session_id = '${session.id}' WHERE id = ${purchaseId}`
        );
        return { checkoutUrl: session.url, purchaseId, baseTokens, bonusTokens, totalTokens: baseTokens + bonusTokens };
      }
    } catch (e) {
      console.error("[ICO] Stripe checkout failed:", e);
    }
    await db2.execute(
      `UPDATE ico_purchases SET status = 'paid', tokens_released = ${tgeReleased}, updated_at = ${Date.now()} WHERE id = ${purchaseId}`
    );
    try {
      const { upsertTokenBalance: upsertTokenBalance2, createTransaction: createTransaction2 } = await Promise.resolve().then(() => (init_db(), db_exports));
      await upsertTokenBalance2(ctx.user.id, "SKY444", tgeReleased);
      await createTransaction2({ userId: ctx.user.id, token: "SKY444", amount: tgeReleased, type: "credit", description: `ICO TGE release \u2014 ${tier.name}` });
    } catch {
    }
    return {
      checkoutUrl: null,
      purchaseId,
      baseTokens,
      bonusTokens,
      totalTokens: baseTokens + bonusTokens,
      devMode: true,
      message: "Dev mode: tokens credited instantly"
    };
  }),
  // Webhook: confirm Stripe payment and release TGE tokens
  confirmPayment: protectedProcedure.input(z27.object({ purchaseId: z27.number(), sessionId: z27.string().optional() })).mutation(async ({ ctx, input }) => {
    const db2 = await getDb();
    if (!db2) return { success: false };
    const rows = await db2.execute(
      `SELECT * FROM ico_purchases WHERE id = ${input.purchaseId} AND user_id = ${ctx.user.id} LIMIT 1`
    );
    const purchase = rows.rows?.[0];
    if (!purchase) return { success: false, error: "Purchase not found" };
    if (purchase.status === "paid") return { success: true, alreadyPaid: true };
    await db2.execute(
      `UPDATE ico_purchases SET status = 'paid', tokens_released = ${parseFloat(purchase.tge_released ?? "0")}, updated_at = ${Date.now()} WHERE id = ${input.purchaseId}`
    );
    try {
      const { upsertTokenBalance: upsertTokenBalance2, createTransaction: createTransaction2 } = await Promise.resolve().then(() => (init_db(), db_exports));
      const tge = parseFloat(purchase.tge_released ?? "0");
      if (tge > 0) {
        await upsertTokenBalance2(ctx.user.id, "SKY444", tge);
        await createTransaction2({ userId: ctx.user.id, token: "SKY444", amount: tge, type: "credit", description: "ICO TGE release" });
      }
    } catch {
    }
    return { success: true };
  }),
  // Claim vested tokens
  claimVested: protectedProcedure.input(z27.object({ purchaseId: z27.number() })).mutation(async ({ ctx, input }) => {
    const db2 = await getDb();
    if (!db2) return { success: false, claimed: 0 };
    const rows = await db2.execute(
      `SELECT * FROM ico_purchases WHERE id = ${input.purchaseId} AND user_id = ${ctx.user.id} AND status = 'paid' LIMIT 1`
    );
    const purchase = rows.rows?.[0];
    if (!purchase) return { success: false, claimed: 0 };
    const claimable = computeClaimable(purchase);
    if (claimable <= 0) return { success: false, claimed: 0, message: "Nothing to claim yet" };
    const newReleased = parseFloat(purchase.tokens_released ?? "0") + claimable;
    await db2.execute(
      `UPDATE ico_purchases SET tokens_released = ${newReleased}, updated_at = ${Date.now()} WHERE id = ${input.purchaseId}`
    );
    try {
      const { upsertTokenBalance: upsertTokenBalance2, createTransaction: createTransaction2 } = await Promise.resolve().then(() => (init_db(), db_exports));
      await upsertTokenBalance2(ctx.user.id, "SKY444", claimable);
      await createTransaction2({ userId: ctx.user.id, token: "SKY444", amount: claimable, type: "credit", description: "ICO vesting claim" });
    } catch {
    }
    return { success: true, claimed: claimable };
  }),
  // AI investment analysis
  getAIAnalysis: protectedProcedure.input(z27.object({ investmentUSD: z27.number(), tierId: z27.string() })).mutation(async ({ input }) => {
    const tier = ICO_TIERS.find((t2) => t2.id === input.tierId);
    if (!tier) throw new Error("Invalid tier");
    const tokens = input.investmentUSD / tier.priceUSD;
    const response = await invokeLLM({
      messages: [
        {
          role: "system",
          content: "You are a crypto investment analyst for SKYCOIN4444 (SKY444). Provide concise, honest analysis. Be specific with numbers."
        },
        {
          role: "user",
          content: `Analyze a $${input.investmentUSD} investment in the ${tier.name} at $${tier.priceUSD}/token. This gives ${tokens.toLocaleString()} SKY444 tokens plus ${tier.bonus}% bonus (${(tokens * tier.bonus / 100).toLocaleString()} extra). Vesting: ${tier.vestingMonths} months with ${tier.cliffMonths} month cliff, ${tier.tgePercent}% at TGE. Platform: AI-powered Web3 social ecosystem combining social media, DeFi, gaming, streaming, marketplace, and charity. Target: $0.10/token at public launch (20x from presale). Provide: 1) ROI scenarios (bear/base/bull), 2) Risk factors, 3) Best strategy for this amount, 4) Vesting impact on liquidity. Keep it under 200 words.`
        }
      ]
    });
    return {
      analysis: response.choices?.[0]?.message?.content ?? "Analysis unavailable",
      tokens,
      bonusTokens: tokens * tier.bonus / 100,
      totalTokens: tokens * (1 + tier.bonus / 100),
      tier
    };
  }),
  // Leaderboard of top ICO contributors
  getLeaderboard: publicProcedure.query(async () => {
    await ensureIcoTables();
    const db2 = await getDb();
    if (!db2) return [];
    try {
      const rows = await db2.execute(
        `SELECT user_id, SUM(usd_amount) as total_usd, SUM(token_amount + bonus_tokens) as total_tokens, COUNT(*) as purchases
         FROM ico_purchases WHERE status = 'paid'
         GROUP BY user_id ORDER BY total_usd DESC LIMIT 20`
      );
      return (rows.rows ?? []).map((r, i) => ({
        rank: i + 1,
        userId: r.user_id,
        totalUSD: parseFloat(r.total_usd ?? "0"),
        totalTokens: parseFloat(r.total_tokens ?? "0"),
        purchases: parseInt(r.purchases ?? "0")
      }));
    } catch {
      return [];
    }
  })
});
function computeClaimable(purchase) {
  const now = Date.now();
  const vestingStart = parseInt(purchase.vesting_start ?? "0");
  const vestingEnd = parseInt(purchase.vesting_end ?? "0");
  const cliffEnd = parseInt(purchase.cliff_end ?? "0");
  const totalTokens = parseFloat(purchase.token_amount ?? "0") + parseFloat(purchase.bonus_tokens ?? "0");
  const tgeReleased = parseFloat(purchase.tge_released ?? "0");
  const alreadyReleased = parseFloat(purchase.tokens_released ?? "0");
  if (now < cliffEnd) return 0;
  if (vestingEnd <= vestingStart) return 0;
  const elapsed = Math.min(now - vestingStart, vestingEnd - vestingStart);
  const vestingProgress = elapsed / (vestingEnd - vestingStart);
  const totalVested = tgeReleased + (totalTokens - tgeReleased) * vestingProgress;
  const claimable = Math.max(0, totalVested - alreadyReleased);
  return Math.floor(claimable * 1e3) / 1e3;
}

// server/coin-economics-router.ts
import { z as z28 } from "zod";
init_db();
init_llm();
var FEE_SCHEDULE = {
  marketplace_sale: { rate: 0.025, label: "Marketplace Sale", treasury: 0.4, creator: 0.4, stakers: 0.2 },
  nft_mint: { rate: 0.05, label: "NFT Mint", treasury: 0.5, creator: 0.3, stakers: 0.2 },
  nft_trade: { rate: 0.025, label: "NFT Trade", treasury: 0.4, creator: 0.4, stakers: 0.2 },
  token_swap: { rate: 3e-3, label: "Token Swap", treasury: 0.5, creator: 0, stakers: 0.5 },
  stream_gift: { rate: 0.1, label: "Stream Gift", treasury: 0.1, creator: 0.7, stakers: 0.2 },
  subscription: { rate: 0.15, label: "Subscription", treasury: 0.2, creator: 0.6, stakers: 0.2 },
  premium_post: { rate: 0.1, label: "Premium Post", treasury: 0.2, creator: 0.6, stakers: 0.2 },
  tournament_entry: { rate: 0.05, label: "Tournament Entry", treasury: 0.3, creator: 0, stakers: 0.3, prize_pool: 0.4 },
  course_purchase: { rate: 0.15, label: "Course Purchase", treasury: 0.2, creator: 0.6, stakers: 0.2 },
  charity_donation: { rate: 0.02, label: "Charity Donation", treasury: 0.5, creator: 0, stakers: 0, charity: 0.5 },
  ai_service: { rate: 0.05, label: "AI Service", treasury: 0.6, creator: 0, stakers: 0.4 },
  advertising: { rate: 0.2, label: "Advertising", treasury: 0.3, creator: 0.5, stakers: 0.2 }
};
var DEMAND_MULTIPLIERS = {
  low: 0.8,
  normal: 1,
  high: 1.2,
  surge: 1.5
};
async function ensureCoinEconomicsTables() {
  const db2 = await getDb();
  if (!db2) return;
  await db2.execute(`
    CREATE TABLE IF NOT EXISTS coin_fee_events (
      id INT AUTO_INCREMENT PRIMARY KEY,
      event_type VARCHAR(50) NOT NULL,
      gross_amount DECIMAL(18,6) NOT NULL,
      fee_amount DECIMAL(18,6) NOT NULL,
      treasury_share DECIMAL(18,6) NOT NULL,
      creator_share DECIMAL(18,6) NOT NULL,
      staker_share DECIMAL(18,6) NOT NULL,
      user_id INT,
      creator_id INT,
      reference_id VARCHAR(100),
      token VARCHAR(20) DEFAULT 'SKY444',
      created_at BIGINT NOT NULL
    )
  `);
  await db2.execute(`
    CREATE TABLE IF NOT EXISTS coin_treasury (
      id INT AUTO_INCREMENT PRIMARY KEY,
      balance DECIMAL(18,6) NOT NULL DEFAULT 0,
      total_accumulated DECIMAL(18,6) NOT NULL DEFAULT 0,
      total_distributed DECIMAL(18,6) NOT NULL DEFAULT 0,
      last_distribution BIGINT,
      updated_at BIGINT NOT NULL
    )
  `);
  await db2.execute(`
    CREATE TABLE IF NOT EXISTS coin_profit_distributions (
      id INT AUTO_INCREMENT PRIMARY KEY,
      epoch INT NOT NULL,
      total_distributed DECIMAL(18,6) NOT NULL,
      staker_pool DECIMAL(18,6) NOT NULL,
      creator_pool DECIMAL(18,6) NOT NULL,
      treasury_retained DECIMAL(18,6) NOT NULL,
      participants INT NOT NULL DEFAULT 0,
      created_at BIGINT NOT NULL
    )
  `);
  await db2.execute(`
    CREATE TABLE IF NOT EXISTS coin_price_history (
      id INT AUTO_INCREMENT PRIMARY KEY,
      token VARCHAR(20) NOT NULL,
      price_usd DECIMAL(18,8) NOT NULL,
      volume_24h DECIMAL(18,2) DEFAULT 0,
      market_cap DECIMAL(18,2) DEFAULT 0,
      demand_level ENUM('low','normal','high','surge') DEFAULT 'normal',
      recorded_at BIGINT NOT NULL
    )
  `);
  const rows = await db2.execute(`SELECT COUNT(*) as cnt FROM coin_treasury`);
  if (rows.rows?.[0]?.cnt === 0) {
    await db2.execute(`INSERT INTO coin_treasury (balance, total_accumulated, total_distributed, updated_at) VALUES (0, 0, 0, ${Date.now()})`);
  }
}
var coinEconomicsRouter = router({
  // Get full fee schedule with current demand multipliers
  getFeeSchedule: publicProcedure.query(async () => {
    const db2 = await getDb();
    let demandLevel = "normal";
    if (db2) {
      try {
        const rows = await db2.execute(
          `SELECT demand_level FROM coin_price_history WHERE token = 'SKY444' ORDER BY recorded_at DESC LIMIT 1`
        );
        demandLevel = rows.rows?.[0]?.demand_level ?? "normal";
      } catch {
      }
    }
    const multiplier = DEMAND_MULTIPLIERS[demandLevel];
    return {
      demandLevel,
      multiplier,
      fees: Object.entries(FEE_SCHEDULE).map(([key, fee]) => ({
        key,
        label: fee.label,
        baseRate: fee.rate,
        effectiveRate: fee.rate * multiplier,
        effectiveRatePct: (fee.rate * multiplier * 100).toFixed(2) + "%",
        routing: {
          treasury: fee.treasury,
          creator: fee.creator,
          stakers: fee.stakers,
          ..."prize_pool" in fee ? { prize_pool: fee.prize_pool } : {},
          ..."charity" in fee ? { charity: fee.charity } : {}
        }
      }))
    };
  }),
  // Get treasury balance and stats
  getTreasury: publicProcedure.query(async () => {
    await ensureCoinEconomicsTables();
    const db2 = await getDb();
    if (!db2) return { balance: 0, totalAccumulated: 0, totalDistributed: 0, lastDistribution: null };
    try {
      const rows = await db2.execute(`SELECT * FROM coin_treasury LIMIT 1`);
      const t2 = rows.rows?.[0] ?? {};
      const feeRows = await db2.execute(
        `SELECT COALESCE(SUM(fee_amount), 0) as total_30d, COALESCE(SUM(treasury_share), 0) as treasury_30d, COUNT(*) as events_30d FROM coin_fee_events WHERE created_at > ${Date.now() - 30 * 24 * 60 * 60 * 1e3}`
      );
      const fee30 = feeRows.rows?.[0] ?? {};
      return {
        balance: parseFloat(t2.balance ?? "0"),
        totalAccumulated: parseFloat(t2.total_accumulated ?? "0"),
        totalDistributed: parseFloat(t2.total_distributed ?? "0"),
        lastDistribution: t2.last_distribution ? parseInt(t2.last_distribution) : null,
        revenue30d: parseFloat(fee30.total_30d ?? "0"),
        treasuryInflow30d: parseFloat(fee30.treasury_30d ?? "0"),
        feeEvents30d: parseInt(fee30.events_30d ?? "0")
      };
    } catch {
      return { balance: 0, totalAccumulated: 0, totalDistributed: 0, lastDistribution: null };
    }
  }),
  // Record a fee event (called internally by other routers)
  recordFeeEvent: protectedProcedure.input(z28.object({
    eventType: z28.string(),
    grossAmount: z28.number(),
    creatorId: z28.number().optional(),
    referenceId: z28.string().optional(),
    token: z28.string().default("SKY444")
  })).mutation(async ({ ctx, input }) => {
    await ensureCoinEconomicsTables();
    const db2 = await getDb();
    if (!db2) return { success: false };
    const feeConfig = FEE_SCHEDULE[input.eventType];
    if (!feeConfig) return { success: false, error: "Unknown event type" };
    const feeAmount = input.grossAmount * feeConfig.rate;
    const treasuryShare = feeAmount * feeConfig.treasury;
    const creatorShare = feeAmount * feeConfig.creator;
    const stakerShare = feeAmount * feeConfig.stakers;
    await db2.execute(
      `INSERT INTO coin_fee_events (event_type, gross_amount, fee_amount, treasury_share, creator_share, staker_share, user_id, creator_id, reference_id, token, created_at)
         VALUES ('${input.eventType}', ${input.grossAmount}, ${feeAmount}, ${treasuryShare}, ${creatorShare}, ${stakerShare}, ${ctx.user.id}, ${input.creatorId ?? "NULL"}, ${input.referenceId ? `'${input.referenceId}'` : "NULL"}, '${input.token}', ${Date.now()})`
    );
    await db2.execute(
      `UPDATE coin_treasury SET balance = balance + ${treasuryShare}, total_accumulated = total_accumulated + ${treasuryShare}, updated_at = ${Date.now()}`
    );
    if (creatorShare > 0 && input.creatorId) {
      try {
        const { upsertTokenBalance: upsertTokenBalance2, createTransaction: createTransaction2 } = await Promise.resolve().then(() => (init_db(), db_exports));
        await upsertTokenBalance2(input.creatorId, input.token, creatorShare);
        await createTransaction2({ userId: input.creatorId, token: input.token, amount: creatorShare, type: "credit", description: `Creator revenue: ${feeConfig.label}` });
      } catch {
      }
    }
    return { success: true, feeAmount, treasuryShare, creatorShare, stakerShare };
  }),
  // Get fee revenue analytics
  getRevenueAnalytics: publicProcedure.input(z28.object({ days: z28.number().default(30) })).query(async ({ input }) => {
    await ensureCoinEconomicsTables();
    const db2 = await getDb();
    if (!db2) return { byType: [], dailyRevenue: [], totals: { fees: 0, treasury: 0, creators: 0, stakers: 0 } };
    try {
      const since = Date.now() - input.days * 24 * 60 * 60 * 1e3;
      const byType = await db2.execute(
        `SELECT event_type, COUNT(*) as count, SUM(fee_amount) as total_fees, SUM(treasury_share) as treasury, SUM(creator_share) as creators, SUM(staker_share) as stakers
           FROM coin_fee_events WHERE created_at > ${since}
           GROUP BY event_type ORDER BY total_fees DESC`
      );
      const totals = await db2.execute(
        `SELECT COALESCE(SUM(fee_amount),0) as fees, COALESCE(SUM(treasury_share),0) as treasury, COALESCE(SUM(creator_share),0) as creators, COALESCE(SUM(staker_share),0) as stakers
           FROM coin_fee_events WHERE created_at > ${since}`
      );
      return {
        byType: (byType.rows ?? []).map((r) => ({
          eventType: r.event_type,
          count: parseInt(r.count ?? "0"),
          totalFees: parseFloat(r.total_fees ?? "0"),
          treasury: parseFloat(r.treasury ?? "0"),
          creators: parseFloat(r.creators ?? "0"),
          stakers: parseFloat(r.stakers ?? "0")
        })),
        totals: {
          fees: parseFloat(totals.rows?.[0]?.fees ?? "0"),
          treasury: parseFloat(totals.rows?.[0]?.treasury ?? "0"),
          creators: parseFloat(totals.rows?.[0]?.creators ?? "0"),
          stakers: parseFloat(totals.rows?.[0]?.stakers ?? "0")
        },
        dailyRevenue: []
      };
    } catch {
      return { byType: [], dailyRevenue: [], totals: { fees: 0, treasury: 0, creators: 0, stakers: 0 } };
    }
  }),
  // Distribute profits to stakers (admin only)
  distributeToStakers: adminProcedure.input(z28.object({ amount: z28.number().min(1), epoch: z28.number() })).mutation(async ({ input }) => {
    await ensureCoinEconomicsTables();
    const db2 = await getDb();
    if (!db2) return { success: false };
    try {
      const stakers = await db2.execute(
        `SELECT user_id, amount FROM staking_positions WHERE status = 'active' ORDER BY amount DESC`
      );
      const rows = stakers.rows ?? [];
      if (rows.length === 0) return { success: false, error: "No active stakers" };
      const totalStaked = rows.reduce((sum4, r) => sum4 + parseFloat(r.amount ?? "0"), 0);
      let distributed = 0;
      for (const staker of rows) {
        const share = parseFloat(staker.amount ?? "0") / totalStaked * input.amount;
        if (share < 1e-3) continue;
        try {
          const { upsertTokenBalance: upsertTokenBalance2, createTransaction: createTransaction2 } = await Promise.resolve().then(() => (init_db(), db_exports));
          await upsertTokenBalance2(staker.user_id, "SKY444", share);
          await createTransaction2({ userId: staker.user_id, token: "SKY444", amount: share, type: "credit", description: `Staking profit distribution epoch ${input.epoch}` });
          distributed += share;
        } catch {
        }
      }
      await db2.execute(
        `INSERT INTO coin_profit_distributions (epoch, total_distributed, staker_pool, creator_pool, treasury_retained, participants, created_at)
           VALUES (${input.epoch}, ${distributed}, ${distributed}, 0, ${input.amount - distributed}, ${rows.length}, ${Date.now()})`
      );
      await db2.execute(
        `UPDATE coin_treasury SET balance = GREATEST(0, balance - ${input.amount}), total_distributed = total_distributed + ${distributed}, last_distribution = ${Date.now()}, updated_at = ${Date.now()}`
      );
      return { success: true, distributed, participants: rows.length };
    } catch (e) {
      return { success: false, error: String(e) };
    }
  }),
  // AI-powered price prediction
  getPricePrediction: publicProcedure.input(z28.object({ token: z28.string().default("SKY444"), horizon: z28.enum(["1d", "7d", "30d", "90d"]).default("30d") })).mutation(async ({ input }) => {
    const response = await invokeLLM({
      messages: [
        {
          role: "system",
          content: "You are a crypto price analyst. Provide concise, data-driven price analysis. Always include specific price targets."
        },
        {
          role: "user",
          content: `Analyze ${input.token} price prediction for ${input.horizon} horizon. Current price: $0.012 (presale). Platform: AI-powered Web3 social ecosystem with DeFi, gaming, streaming, marketplace, charity. Token utility: governance, staking (up to 35% APY), fee discounts, premium features. Total supply: 1B tokens. Provide: 1) Bear/Base/Bull price targets, 2) Key catalysts, 3) Risk factors, 4) Confidence score. Keep under 150 words.`
        }
      ]
    });
    return {
      prediction: response.choices?.[0]?.message?.content ?? "Prediction unavailable",
      token: input.token,
      horizon: input.horizon,
      currentPrice: 0.012,
      generatedAt: Date.now()
    };
  }),
  // Get distribution history
  getDistributionHistory: publicProcedure.query(async () => {
    await ensureCoinEconomicsTables();
    const db2 = await getDb();
    if (!db2) return [];
    try {
      const rows = await db2.execute(
        `SELECT * FROM coin_profit_distributions ORDER BY created_at DESC LIMIT 20`
      );
      return (rows.rows ?? []).map((r) => ({
        epoch: r.epoch,
        totalDistributed: parseFloat(r.total_distributed ?? "0"),
        stakerPool: parseFloat(r.staker_pool ?? "0"),
        creatorPool: parseFloat(r.creator_pool ?? "0"),
        treasuryRetained: parseFloat(r.treasury_retained ?? "0"),
        participants: parseInt(r.participants ?? "0"),
        createdAt: parseInt(r.created_at ?? "0")
      }));
    } catch {
      return [];
    }
  }),
  // Get my earnings from platform fees
  getMyEarnings: protectedProcedure.query(async ({ ctx }) => {
    await ensureCoinEconomicsTables();
    const db2 = await getDb();
    if (!db2) return { creatorEarnings: 0, stakerEarnings: 0, totalEarnings: 0, breakdown: [] };
    try {
      const creatorRows = await db2.execute(
        `SELECT COALESCE(SUM(creator_share), 0) as total FROM coin_fee_events WHERE creator_id = ${ctx.user.id}`
      );
      const creatorEarnings = parseFloat(creatorRows.rows?.[0]?.total ?? "0");
      return {
        creatorEarnings,
        stakerEarnings: 0,
        // From distribution history
        totalEarnings: creatorEarnings,
        breakdown: []
      };
    } catch {
      return { creatorEarnings: 0, stakerEarnings: 0, totalEarnings: 0, breakdown: [] };
    }
  })
});

