async function addXP(userId, amount) {
  const db2 = await getDb();
  if (!db2) return { newXp: 0, newLevel: 1, leveledUp: false };
  try {
    await ensureQuestTables();
    await db2.execute(`INSERT INTO user_xp (user_id, xp, level, updated_at) VALUES (${userId}, ${amount}, 1, ${Date.now()})
      ON DUPLICATE KEY UPDATE xp = xp + ${amount}, updated_at = ${Date.now()}`);
    const rows = await db2.execute(`SELECT xp, level FROM user_xp WHERE user_id = ${userId}`);
    const r = rows.rows?.[0];
    const xp = Number(r?.xp ?? amount);
    const newLevel = Math.floor(1 + Math.sqrt(xp / 100));
    const oldLevel = Number(r?.level ?? 1);
    if (newLevel > oldLevel) {
      await db2.execute(`UPDATE user_xp SET level = ${newLevel} WHERE user_id = ${userId}`);
    }
    return { newXp: xp, newLevel, leveledUp: newLevel > oldLevel };
  } catch {
    return { newXp: 0, newLevel: 1, leveledUp: false };
  }
}
