async function ensureICOTables() {
  const db2 = await getDb();
  if (!db2) return;
  try {
    await db2.execute(`CREATE TABLE IF NOT EXISTS ico_purchases (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      tier_id VARCHAR(20) NOT NULL,
      usd_amount DECIMAL(12,2) NOT NULL,
      token_amount DECIMAL(18,8) NOT NULL,
      bonus_tokens DECIMAL(18,8) DEFAULT 0,
      stripe_session_id VARCHAR(200),
      stripe_payment_intent VARCHAR(200),
      status ENUM('pending','completed','failed','refunded') DEFAULT 'pending',
      vesting_start BIGINT DEFAULT 0,
      vesting_end BIGINT DEFAULT 0,
      tokens_released DECIMAL(18,8) DEFAULT 0,
      referral_code VARCHAR(50),
      created_at BIGINT DEFAULT 0,
      updated_at BIGINT DEFAULT 0,
      INDEX idx_user (user_id),
      INDEX idx_session (stripe_session_id)
    )`);
    await db2.execute(`CREATE TABLE IF NOT EXISTS ico_referrals (
      id INT AUTO_INCREMENT PRIMARY KEY,
      referrer_id INT NOT NULL,
      referred_user_id INT NOT NULL,
      referral_code VARCHAR(50) NOT NULL,
      commission_pct DECIMAL(5,2) DEFAULT 5.00,
      commission_earned DECIMAL(18,8) DEFAULT 0,
      status ENUM('active','paid','expired') DEFAULT 'active',
      created_at BIGINT DEFAULT 0,
      UNIQUE KEY uq_referred (referred_user_id),
      INDEX idx_referrer (referrer_id)
    )`);
    await db2.execute(`CREATE TABLE IF NOT EXISTS ico_vesting_releases (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      purchase_id INT NOT NULL,
      amount DECIMAL(18,8) NOT NULL,
      released_at BIGINT NOT NULL,
      tx_hash VARCHAR(200),
      created_at BIGINT DEFAULT 0
    )`);
    await db2.execute(`CREATE TABLE IF NOT EXISTS ico_whitelist (
      id INT AUTO_INCREMENT PRIMARY KEY,
      user_id INT NOT NULL,
      tier_id VARCHAR(20) NOT NULL,
      whitelisted_at BIGINT DEFAULT 0,
      max_allocation DECIMAL(12,2) DEFAULT 5000,
      UNIQUE KEY uq_user_tier (user_id, tier_id)
    )`);
    await db2.execute(`CREATE TABLE IF NOT EXISTS ico_burn_log (
      id INT AUTO_INCREMENT PRIMARY KEY,
      amount DECIMAL(18,8) NOT NULL,
      reason VARCHAR(200) NOT NULL,
      tx_hash VARCHAR(200),
      burned_at BIGINT DEFAULT 0
    )`);
  } catch {
  }
}
async function getICOStats() {
  const db2 = await getDb();
  if (!db2) return { totalRaised: 0, totalInvestors: 0, tokensSold: 0, currentTier: "pre", progress: 0, burnedTokens: 0 };
  try {
    const [raised, burned] = await Promise.all([
      db2.execute(`SELECT COALESCE(SUM(usd_amount),0) as total, COUNT(DISTINCT user_id) as investors, COALESCE(SUM(token_amount + bonus_tokens),0) as tokens FROM ico_purchases WHERE status = 'completed'`),
      db2.execute(`SELECT COALESCE(SUM(amount),0) as total FROM ico_burn_log`)
    ]);
    const r = raised.rows?.[0];
    const b = burned.rows?.[0];
    const totalRaised = Number(r?.total ?? 0);
    const tokensSold = Number(r?.tokens ?? 0);
    const currentTier = TOKENOMICS.tiers.find((t2) => t2.status === "active")?.id ?? "pre";
    const activeTier = TOKENOMICS.tiers.find((t2) => t2.id === currentTier);
    const progress = activeTier ? Math.min(100, totalRaised / activeTier.hardCap * 100) : 0;
    return {
      totalRaised,
      totalInvestors: Number(r?.investors ?? 0),
      tokensSold,
      currentTier,
      progress,
      burnedTokens: Number(b?.total ?? 0)
    };
  } catch {
    return { totalRaised: 0, totalInvestors: 0, tokensSold: 0, currentTier: "pre", progress: 0, burnedTokens: 0 };
  }
}
