// server/stripe-router.ts
import { z as z36 } from "zod";
import Stripe3 from "stripe";

// server/db-language-exchange.ts
init_db();
init_drizzle();
import { eq as eq26, and as and19, desc as desc23, like as like6, lte as lte10 } from "drizzle-orm";
async function getTeacherProfile(userId) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database connection failed");
  return await db2.select().from(teacherProfiles).where(eq26(teacherProfiles.userId, userId)).then((rows) => rows[0]);
}
async function createTeacherBooking(data) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database connection failed");
  return await db2.insert(teacherBookings).values({
    studentId: data.studentId,
    teacherId: data.teacherId,
    startTime: data.startTime,
    duration: data.duration,
    topic: data.topic,
    notes: data.notes,
    amount: data.amount,
    status: "pending",
    paymentStatus: "pending"
  });
}
async function getTeacherBookings(userId, type = "student") {
  const db2 = await getDb();
  if (!db2) throw new Error("Database connection failed");
  const condition = type === "student" ? eq26(teacherBookings.studentId, userId) : eq26(teacherBookings.teacherId, userId);
  return await db2.select().from(teacherBookings).where(condition).orderBy(desc23(teacherBookings.startTime));
}
async function updateTeacherBooking(bookingId, data) {
  const db2 = await getDb();
  if (!db2) throw new Error("Database connection failed");
  return await db2.update(teacherBookings).set(data).where(eq26(teacherBookings.id, bookingId));
}

// server/stripe-router.ts
var _stripe = null;
function getStripe2() {
  if (!process.env.STRIPE_SECRET_KEY) {
    throw new Error("Stripe is not configured (STRIPE_SECRET_KEY missing)");
  }
  if (!_stripe) {
    _stripe = new Stripe3(process.env.STRIPE_SECRET_KEY, {
      apiVersion: "2026-05-27.dahlia"
    });
  }
  return _stripe;
}
var stripeRouter = router({
  // Create checkout session for teacher booking
  createTeacherBookingCheckout: protectedProcedure.input(
    z36.object({
      teacherId: z36.number(),
      startTime: z36.date(),
      duration: z36.number(),
      // minutes
      topic: z36.string().optional(),
      notes: z36.string().optional()
    })
  ).mutation(async ({ input, ctx }) => {
    const teacher = await getTeacherProfile(input.teacherId);
    if (!teacher) {
      throw new Error("Teacher not found");
    }
    const hourlyRateInCents = teacher.hourlyRate;
    const durationInHours = input.duration / 60;
    const amountInCents = Math.round(hourlyRateInCents * durationInHours);
    const booking = await createTeacherBooking({
      studentId: ctx.user.id,
      teacherId: input.teacherId,
      startTime: input.startTime,
      duration: input.duration,
      topic: input.topic,
      notes: input.notes,
      amount: amountInCents
    });
    const session = await getStripe2().checkout.sessions.create({
      payment_method_types: ["card"],
      line_items: [
        {
          price_data: {
            currency: "usd",
            product_data: {
              name: `Language Lesson with ${teacher.language}`,
              description: `${input.duration} minutes with teacher`
            },
            unit_amount: amountInCents
          },
          quantity: 1
        }
      ],
      mode: "payment",
      success_url: `${ctx.req.headers.origin || "http://localhost:3000"}/teacher-booking/success?session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${ctx.req.headers.origin || "http://localhost:3000"}/teacher-booking/cancel`,
      customer_email: ctx.user.email || void 0,
      metadata: {
        bookingId: booking.insertId?.toString() || "unknown",
        studentId: ctx.user.id.toString(),
        teacherId: input.teacherId.toString(),
        startTime: input.startTime.toISOString()
      }
    });
    return {
      sessionId: session.id,
      url: session.url
    };
  }),
  // Confirm payment and update booking
  confirmTeacherBookingPayment: protectedProcedure.input(
    z36.object({
      sessionId: z36.string()
    })
  ).mutation(async ({ input }) => {
    const session = await getStripe2().checkout.sessions.retrieve(input.sessionId);
    if (session.payment_status !== "paid") {
      throw new Error("Payment not completed");
    }
    const bookingId = parseInt(session.metadata?.bookingId || "0");
    if (!bookingId) {
      throw new Error("Invalid booking ID");
    }
    await updateTeacherBooking(bookingId, {
      paymentStatus: "paid",
      stripePaymentIntentId: session.payment_intent || "",
      status: "confirmed"
    });
    return {
      success: true,
      bookingId
    };
  }),
  // Get teacher's earnings
  getTeacherEarnings: protectedProcedure.query(async ({ ctx }) => {
    const teacher = await getTeacherProfile(ctx.user.id);
    if (!teacher) {
      return {
        totalEarnings: 0,
        totalSessions: 0,
        averageRating: 0
      };
    }
    return {
      totalEarnings: teacher.totalEarnings || 0,
      totalSessions: teacher.totalStudents || 0,
      averageRating: teacher.rating || 0
    };
  }),
  // Get teacher's bookings
  getTeacherBookingHistory: protectedProcedure.query(async ({ ctx }) => {
    const bookings = await getTeacherBookings(ctx.user.id, "teacher");
    return bookings;
  }),
  // Get student's bookings
  getStudentBookingHistory: protectedProcedure.query(async ({ ctx }) => {
    const bookings = await getTeacherBookings(ctx.user.id, "student");
    return bookings;
  }),
  // Webhook handler for Stripe events
  handleWebhook: publicProcedure.input(
    z36.object({
      event: z36.any()
    })
  ).mutation(async ({ input }) => {
    const event = input.event;
    switch (event.type) {
      case "payment_intent.succeeded":
        const paymentIntent = event.data.object;
        console.log("[Stripe] Payment succeeded:", paymentIntent.id);
        break;
      case "payment_intent.payment_failed":
        console.log("[Stripe] Payment failed:", event.data.object.id);
        break;
      case "charge.refunded":
        console.log("[Stripe] Refund processed:", event.data.object.id);
        break;
      default:
        console.log("[Stripe] Unhandled event type:", event.type);
    }
    return { received: true };
  }),
  // Create Stripe Connect account for teacher
  createTeacherStripeAccount: protectedProcedure.input(
    z36.object({
      email: z36.string().email(),
      country: z36.string().default("US")
    })
  ).mutation(async ({ input, ctx }) => {
    try {
      const account = await getStripe2().accounts.create({
        type: "express",
        email: input.email,
        country: input.country,
        capabilities: {
          card_payments: { requested: true },
          transfers: { requested: true }
        }
      });
      return {
        accountId: account.id,
        onboardingUrl: await getStripe2().accountLinks.create({
          account: account.id,
          type: "account_onboarding",
          refresh_url: `${ctx.req.headers.origin || "http://localhost:3000"}/teacher/stripe/refresh`,
          return_url: `${ctx.req.headers.origin || "http://localhost:3000"}/teacher/stripe/return`
        })
      };
    } catch (error) {
      console.error("[Stripe] Error creating account:", error);
      throw error;
    }
  }),
  // Get payment methods
  getPaymentMethods: protectedProcedure.query(async ({ ctx }) => {
    try {
      const paymentMethods = await getStripe2().paymentMethods.list({
        type: "card"
      });
      return paymentMethods.data.map((pm) => ({
        id: pm.id,
        brand: pm.card?.brand,
        last4: pm.card?.last4,
        expMonth: pm.card?.exp_month,
        expYear: pm.card?.exp_year
      }));
    } catch (error) {
      console.error("[Stripe] Error fetching payment methods:", error);
      return [];
    }
  }),
  // Create refund
  createRefund: protectedProcedure.input(
    z36.object({
      bookingId: z36.number(),
      reason: z36.enum(["requested_by_customer", "duplicate", "fraudulent"])
    })
  ).mutation(async ({ input }) => {
    const bookings = await getTeacherBookings(input.bookingId, "student");
    const booking = Array.isArray(bookings) ? bookings[0] : bookings;
    if (!booking || !booking.stripePaymentIntentId) {
      throw new Error("Booking or payment not found");
    }
    try {
      const refund = await getStripe2().refunds.create({
        payment_intent: booking.stripePaymentIntentId,
        reason: input.reason
      });
      const bookingId = booking.id;
      await updateTeacherBooking(bookingId, {
        paymentStatus: "refunded",
        status: "cancelled"
      });
      return {
        refundId: refund.id,
        amount: refund.amount,
        status: refund.status
      };
    } catch (error) {
      console.error("[Stripe] Error creating refund:", error);
      throw error;
    }
  })
});

